import { Injectable, inject, signal, computed } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { firstValueFrom } from 'rxjs';

import { AuthTokenManagerService } from './auth-token-manager.service';
import { ApiUrlService } from './api-url.service';
import {
  ConversationSummary,
  ConversationDetail,
  ConversationUpdate,
  ConversationListResponse,
  SessionDetailResponse,
  GroupedConversations,
  AnalyticsSnapshotMeta,
} from '../interfaces/conversation.interface';
import {
  ChatMessage,
  ChatMessageMetadata,
  ChatContext,
  SessionStatus,
  ActionType,
} from '../../features/development/components/analytical-report/chat/models/chat.interface';
import { ClientDataService } from '../../features/clients/services/client-data.service';
import { isNullOrUndefined } from '../../shared/utils';
import { ReportGenerationService } from './report-generation.service';
import { cronToHuman, getReportTypeLabel } from '../utils/schedule.utils';

@Injectable({ providedIn: 'root' })
export class ConversationHistoryService {
  private readonly http = inject(HttpClient);
  private readonly authTokenManagerService = inject(AuthTokenManagerService);
  private readonly apiUrlService = inject(ApiUrlService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly reportGenerationService = inject(ReportGenerationService);

  private readonly chatApiBaseUrl = signal(
    this.apiUrlService.getCurrentApiUrl(),
  );

  // ============================================================================
  // State Signals
  // ============================================================================

  private readonly _conversations = signal<ConversationSummary[]>([]);
  private readonly _isLoading = signal(false);
  private readonly _selectedConversationId = signal<string | null>(null);
  private readonly _error = signal<string | null>(null);

  readonly conversations = this._conversations.asReadonly();
  readonly isLoading = this._isLoading.asReadonly();
  readonly selectedConversationId = this._selectedConversationId.asReadonly();
  readonly error = this._error.asReadonly();

  readonly groupedConversations = computed(() =>
    this.groupByDate(this._conversations()),
  );

  // ============================================================================
  // API Methods
  // ============================================================================

  async loadConversations(silent = false): Promise<ConversationSummary[]> {
    if (!silent) this._isLoading.set(true);
    this._error.set(null);

    try {
      const response = await firstValueFrom(
        this.http.get<ConversationListResponse>(
          `${this.chatApiBaseUrl()}/chat/sessions`,
          {
            headers: {
              'x-access-token':
                this.authTokenManagerService.getAccessToken() ?? '',
              'x-base-url': this.apiUrlService
                .getCurrentApiUrl()
                .replace(/^https?:\/\//, ''),
            },
            params: {
              company_id: this.getClientId(),
              limit: '100',
              offset: '0',
            },
          },
        ),
      );

      const conversations = response.sessions;
      this._conversations.set(conversations);
      return conversations;
    } catch (err) {
      const errorMessage =
        err instanceof Error ? err.message : 'Failed to load conversations';
      this._error.set(errorMessage);
      return [];
    } finally {
      if (!silent) this._isLoading.set(false);
    }
  }

  async loadConversation(id: string): Promise<ConversationDetail> {
    const [raw, analyticsSnapshots, schedules] = await Promise.all([
      firstValueFrom(
        this.http.get<SessionDetailResponse>(
          `${this.chatApiBaseUrl()}/chat/sessions/${id}`,
          {
            headers: {
              'x-access-token':
                this.authTokenManagerService.getAccessToken() ?? '',
              'x-base-url': this.apiUrlService
                .getCurrentApiUrl()
                .replace(/^https?:\/\//, ''),
            },
            params: {
              company_id: this.getClientId(),
            },
          },
        ),
      ),
      this.loadAnalyticsSnapshots(id),
      this.reportGenerationService.listSchedules().catch(() => []),
    ]);

    const detail = this.mapSessionDetailToConversation(raw);
    detail.analyticsSnapshots = analyticsSnapshots;

    const reportTypes = this.reportGenerationService.getReportTypes();
    const scheduleMessages: ChatMessage[] = schedules
      .filter((item) => item.conversation_id === id)
      .map((item) => ({
        id: `schedule-${item.id}`,
        sessionId: id,
        sender: 'assistant' as const,
        content: `I've set up a scheduled ${getReportTypeLabel(item.report_config.report_type, reportTypes)} report for you.`,
        timestamp: new Date(item.created_at),
        status: 'delivered' as const,
        metadata: {
          interactiveType: 'scheduled_report' as const,
          scheduledReport: {
            scheduleId: item.id,
            reportType: item.report_config.report_type,
            cronHuman: cronToHuman(item.schedule),
            nextRun: item.next_run,
            isActive: item.is_active,
          },
        },
      }));

    detail.messages = [...detail.messages, ...scheduleMessages].sort(
      (a, b) => a.timestamp.getTime() - b.timestamp.getTime(),
    );

    return detail;
  }

  async loadAnalyticsSnapshots(
    conversationId: string,
  ): Promise<AnalyticsSnapshotMeta[]> {
    try {
      const response = await firstValueFrom(
        this.http.get<{ snapshots: AnalyticsSnapshotMeta[] }>(
          `${this.chatApiBaseUrl()}/analytics/snapshots`,
          {
            headers: {
              'x-access-token':
                this.authTokenManagerService.getAccessToken() ?? '',
              'x-base-url': this.apiUrlService
                .getCurrentApiUrl()
                .replace(/^https?:\/\//, ''),
            },
            params: {
              conversation_id: conversationId,
              company_id: this.getClientId(),
            },
          },
        ),
      );
      return response.snapshots ?? [];
    } catch {
      return [];
    }
  }

  async loadFullSnapshot(
    conversationId: string,
    snapshotId: string,
  ): Promise<unknown | null> {
    try {
      const response = await firstValueFrom(
        this.http.get<{ analytics: unknown }>(
          `${this.chatApiBaseUrl()}/analytics/snapshots`,
          {
            headers: {
              'x-access-token':
                this.authTokenManagerService.getAccessToken() ?? '',
              'x-base-url': this.apiUrlService
                .getCurrentApiUrl()
                .replace(/^https?:\/\//, ''),
            },
            params: {
              conversation_id: conversationId,
              snapshot_id: snapshotId,
              company_id: this.getClientId(),
            },
          },
        ),
      );
      return response.analytics ?? null;
    } catch {
      return null;
    }
  }

  async updateConversation(
    id: string,
    updates: ConversationUpdate,
  ): Promise<void> {
    await firstValueFrom(
      this.http.patch<void>(`${this.chatApiBaseUrl()}/chat/sessions/${id}`, {
        ...updates,
        auth_token: this.authTokenManagerService.getAccessToken() ?? '',
        base_url: this.apiUrlService
          .getCurrentApiUrl()
          .replace(/^https?:\/\//, ''),
      }),
    );
  }

  async deleteConversation(id: string): Promise<void> {
    await firstValueFrom(
      this.http.delete<void>(`${this.chatApiBaseUrl()}/chat/sessions/${id}`, {
        headers: {
          'x-access-token': this.authTokenManagerService.getAccessToken() ?? '',
          'x-base-url': this.apiUrlService
            .getCurrentApiUrl()
            .replace(/^https?:\/\//, ''),
        },
        params: {
          company_id: this.getClientId(),
        },
      }),
    );
  }

  // ============================================================================
  // Helper Methods
  // ============================================================================

  getClientId(): string {
    const clientId = this.clientDataService.getSelectedClient()?.id;
    if (isNullOrUndefined(clientId)) throw new Error('Client Id is null');
    return clientId;
  }

  selectConversation(id: string): void {
    this._selectedConversationId.set(id);
  }

  refreshList(): void {
    this.loadConversations(true).catch(() => {
      // Error is already captured in _error signal
    });
  }

  private mapSessionDetailToConversation(
    raw: SessionDetailResponse,
  ): ConversationDetail {
    const ctx = raw.context;
    const context: ChatContext = {
      clientId: ctx.client_id,
      clientName: ctx.client_name,
      dateRange: {
        startDate: ctx.date_range?.start_date ?? '',
        endDate: ctx.date_range?.end_date ?? '',
      },
      vehicleIds: ctx.vehicle_ids ?? [],
      vehicleNames: ctx.vehicle_names ?? {},
      dataTypes: (ctx.data_types ?? []) as ChatContext['dataTypes'],
      hasDataContext: ctx.has_data_context ?? false,
    };

    const messages: ChatMessage[] = (raw.messages ?? []).map((msg) => {
      const m: Record<string, unknown> | undefined = isNullOrUndefined(
        msg.metadata,
      )
        ? undefined
        : msg.metadata;
      const metadata: ChatMessageMetadata | undefined =
        m === undefined
          ? undefined
          : {
              ...(m['suggested_actions'] === undefined
                ? {}
                : {
                    suggestedActions: m[
                      'suggested_actions'
                    ] as ChatMessageMetadata['suggestedActions'],
                  }),
              ...(m['selected_actions'] === undefined
                ? {}
                : {
                    selectedActions: (
                      m['selected_actions'] as {
                        action_id: string;
                        label: string;
                        action_type: string;
                        value: string;
                      }[]
                    ).map((a) => ({
                      id: a.action_id,
                      label: a.label,
                      action: a.action_type as ActionType,
                      value: a.value,
                    })),
                  }),
              ...(m['interactive_type'] === undefined
                ? {}
                : {
                    interactiveType: m[
                      'interactive_type'
                    ] as ChatMessageMetadata['interactiveType'],
                  }),
              ...(m['query_update'] === undefined
                ? {}
                : {
                    queryUpdate: m[
                      'query_update'
                    ] as ChatMessageMetadata['queryUpdate'],
                  }),
            };

      return {
        id: msg.id,
        sessionId: raw.session_id,
        sender: msg.role === 'user' ? 'user' : 'assistant',
        content: msg.content,
        timestamp: new Date(msg.timestamp),
        status: 'delivered' as const,
        ...(metadata ? { metadata } : {}),
      };
    });

    return {
      id: raw.session_id,
      title: '',
      visibility: 'private',
      status: (raw.status as SessionStatus) ?? 'active',
      user_id: '',
      company_id: this.getClientId(),
      created_at: raw.created_at,
      last_activity: raw.last_activity,
      message_count: raw.message_count ?? messages.length,
      has_report: (raw.report_files?.length ?? 0) > 0,
      messages,
      context,
      current_query: raw.current_query ?? '',
      query_confidence: raw.query_confidence ?? 0,
      report_files: raw.report_files ?? [],
    };
  }

  private groupByDate(
    conversations: ConversationSummary[],
  ): GroupedConversations {
    const now = new Date();
    const startOfToday = new Date(
      now.getFullYear(),
      now.getMonth(),
      now.getDate(),
    );

    const result: GroupedConversations = {
      today: [],
      yesterday: [],
      last7Days: [],
      last30Days: [],
      older: [],
    };

    for (const conversation of conversations) {
      const activityDate = new Date(conversation.last_activity);
      const startOfActivity = new Date(
        activityDate.getFullYear(),
        activityDate.getMonth(),
        activityDate.getDate(),
      );

      const diffDays = Math.round(
        (startOfToday.getTime() - startOfActivity.getTime()) /
          (1000 * 60 * 60 * 24),
      );

      if (diffDays === 0) {
        result.today.push(conversation);
      } else if (diffDays === 1) {
        result.yesterday.push(conversation);
      } else if (diffDays <= 7) {
        result.last7Days.push(conversation);
      } else if (diffDays <= 30) {
        result.last30Days.push(conversation);
      } else {
        result.older.push(conversation);
      }
    }

    const sortDesc = (a: ConversationSummary, b: ConversationSummary) =>
      new Date(b.last_activity).getTime() - new Date(a.last_activity).getTime();

    result.today.sort(sortDesc);
    result.yesterday.sort(sortDesc);
    result.last7Days.sort(sortDesc);
    result.last30Days.sort(sortDesc);
    result.older.sort(sortDesc);

    return result;
  }
}
