import { Component, computed, input, output, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';

import {
  ReportGenerationRequest,
  ScheduleConfig,
} from '../../../../../../../core/interfaces/report-generation.interface';

export interface ScheduleConfigSelection {
  reportConfig: ReportGenerationRequest;
  schedule: ScheduleConfig;
}

const FREQUENCY_OPTIONS = [
  { label: 'Daily', value: 'daily' as const },
  { label: 'Weekly', value: 'weekly' as const },
  { label: 'Monthly', value: 'monthly' as const },
];

const DAY_OF_WEEK_OPTIONS = [
  { label: 'Monday', value: 1 },
  { label: 'Tuesday', value: 2 },
  { label: 'Wednesday', value: 3 },
  { label: 'Thursday', value: 4 },
  { label: 'Friday', value: 5 },
  { label: 'Saturday', value: 6 },
  { label: 'Sunday', value: 0 },
];

const DATE_RANGE_UNIT_OPTIONS = [
  { label: 'Days', value: 'days' as const },
  { label: 'Weeks', value: 'weeks' as const },
  { label: 'Months', value: 'months' as const },
];

const TIMEZONE_OPTIONS = [
  'Africa/Johannesburg',
  'UTC',
  'Europe/London',
  'Europe/Paris',
  'America/New_York',
  'America/Chicago',
  'America/Denver',
  'America/Los_Angeles',
  'Asia/Dubai',
  'Asia/Singapore',
  'Australia/Sydney',
].map((tz) => ({ label: tz, value: tz }));

@Component({
  selector: 'app-inline-schedule-config',
  imports: [CommonModule, FormsModule, ButtonModule],
  templateUrl: './inline-schedule-config.component.html',
  styleUrl: './inline-schedule-config.component.scss',
})
export class InlineScheduleConfigComponent {
  // Inputs
  reportConfig = input.required<ReportGenerationRequest>();
  isLoading = input<boolean>(false);

  // Outputs
  createSchedule = output<ScheduleConfigSelection>();
  cancelSchedule = output<void>();

  // Constants exposed to template
  readonly frequencyOptions = FREQUENCY_OPTIONS;
  readonly dayOfWeekOptions = DAY_OF_WEEK_OPTIONS;
  readonly dateRangeUnitOptions = DATE_RANGE_UNIT_OPTIONS;
  readonly timezoneOptions = TIMEZONE_OPTIONS;

  // State
  frequency = signal<'daily' | 'weekly' | 'monthly'>('weekly');
  dayOfWeek = signal<number>(1);
  dayOfMonth = signal<number>(1);
  hour = signal<number>(6);
  minute = signal<number>(0);
  timezone = signal<string>('Africa/Johannesburg');
  rangeValue = signal<number>(7);
  rangeUnit = signal<'days' | 'weeks' | 'months'>('days');

  // Computed
  readonly isWeekly = computed(() => this.frequency() === 'weekly');
  readonly isMonthly = computed(() => this.frequency() === 'monthly');

  readonly cronExpression = computed(() => {
    const h = this.hour();
    const m = this.minute();
    switch (this.frequency()) {
      case 'daily':
        return `${m} ${h} * * *`;
      case 'weekly':
        return `${m} ${h} * * ${this.dayOfWeek()}`;
      case 'monthly':
        return `${m} ${h} ${this.dayOfMonth()} * *`;
    }
  });

  readonly humanReadableSummary = computed(() => {
    const timeStr = `${String(this.hour()).padStart(2, '0')}:${String(this.minute()).padStart(2, '0')}`;
    const tz = this.timezone().split('/').pop() ?? this.timezone();
    let freqStr: string;
    switch (this.frequency()) {
      case 'daily':
        freqStr = `Every day at ${timeStr} ${tz}`;
        break;
      case 'weekly': {
        const day =
          DAY_OF_WEEK_OPTIONS.find((d) => d.value === this.dayOfWeek())
            ?.label ?? '';
        freqStr = `Every ${day} at ${timeStr} ${tz}`;
        break;
      }
      case 'monthly':
        freqStr = `Monthly on day ${this.dayOfMonth()} at ${timeStr} ${tz}`;
        break;
    }
    return `${freqStr}, last ${this.rangeValue()} ${this.rangeUnit()} of data`;
  });

  onFrequencyChange(value: string): void {
    this.frequency.set(value as 'daily' | 'weekly' | 'monthly');
  }

  onDayOfWeekChange(value: string): void {
    this.dayOfWeek.set(Number(value));
  }

  onRangeUnitChange(value: string): void {
    this.rangeUnit.set(value as 'days' | 'weeks' | 'months');
  }

  onConfirm(): void {
    this.createSchedule.emit({
      reportConfig: this.reportConfig(),
      schedule: {
        cron: this.cronExpression(),
        timezone: this.timezone(),
        relative_date_range: {
          unit: this.rangeUnit(),
          value: this.rangeValue(),
        },
      },
    });
  }

  onCancel(): void {
    this.cancelSchedule.emit();
  }
}
