import {
  Component,
  computed,
  effect,
  inject,
  input,
  output,
  signal,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';

import { ReportGenerationService } from '../../../../../../../core/services/report-generation.service';
import { isDefined } from '../../../../../../../shared/utils';
import {
  ColumnCategory,
  ColumnDefinition,
  ReportType,
} from '../../../../../../../core/interfaces/report-generation.interface';

export interface ReportConfigSelection {
  reportType: ReportType;
  outputFormat: 'csv' | 'xlsx';
  includeAiAnalysis: boolean;
  columns: string[];
  columnCategories: ColumnCategory[];
}

const OUTPUT_FORMAT_OPTIONS = [
  { label: 'CSV', value: 'csv' as const },
  { label: 'XLSX', value: 'xlsx' as const },
];

@Component({
  selector: 'app-inline-report-config',
  imports: [CommonModule, FormsModule, ButtonModule],
  templateUrl: './inline-report-config.component.html',
  styleUrl: './inline-report-config.component.scss',
})
export class InlineReportConfigComponent {
  private readonly reportGenerationService = inject(ReportGenerationService);

  // Inputs
  initialReportType = input<ReportType | null>(null);
  hideConfirmButton = input(false);

  // Output
  reportConfigSelected = output<ReportConfigSelection>();

  // Constants exposed to template
  readonly reportTypes = this.reportGenerationService.getReportTypes();
  readonly outputFormatOptions = OUTPUT_FORMAT_OPTIONS;

  // State
  selectedReportType = signal<ReportType | null>(null);

  constructor() {
    effect(
      () => {
        const initial = this.initialReportType();
        if (initial) this.selectReportType(initial);
      },
      { allowSignalWrites: true },
    );
  }
  outputFormat = signal<'csv' | 'xlsx'>('xlsx');
  selectedColumns = signal<Set<string>>(new Set());

  // Computed
  readonly availableColumns = computed(() => {
    const type = this.selectedReportType();
    return type ? this.reportGenerationService.getAvailableColumns(type) : [];
  });

  readonly columnsByCategory = computed(() => {
    const cols = this.availableColumns();
    const map = new Map<ColumnCategory, ColumnDefinition[]>();
    for (const col of cols) {
      if (!map.has(col.category)) map.set(col.category, []);
      const entry = map.get(col.category);
      if (isDefined(entry)) entry.push(col);
    }
    return map;
  });

  readonly categoryKeys = computed(() =>
    Array.from(this.columnsByCategory().keys()),
  );

  readonly selectedColumnCount = computed(() => this.selectedColumns().size);

  readonly canConfirm = computed(
    () => this.selectedReportType() !== null && this.selectedColumns().size > 0,
  );

  readonly allColumnsSelected = computed(
    () => this.selectedColumns().size === this.availableColumns().length,
  );

  readonly formattedSummary = computed(() => {
    const type = this.reportTypes.find(
      (r) => r.report_type === this.selectedReportType(),
    );
    const count = this.selectedColumnCount();
    const fmt = this.outputFormat().toUpperCase();
    return `${type?.display_name ?? ''} — ${count} columns — ${fmt}`;
  });

  // Methods
  selectReportType(type: ReportType): void {
    this.selectedReportType.set(type);
    const defaults = this.reportGenerationService.getDefaultColumns(type);
    this.selectedColumns.set(new Set(defaults));
  }

  toggleColumn(key: string): void {
    this.selectedColumns.update((current) => {
      const next = new Set(current);
      if (next.has(key)) next.delete(key);
      else next.add(key);
      return next;
    });
  }

  isColumnSelected(key: string): boolean {
    return this.selectedColumns().has(key);
  }

  selectAllColumns(): void {
    this.selectedColumns.set(
      new Set(this.availableColumns().map((c) => c.key)),
    );
  }

  clearColumns(): void {
    this.selectedColumns.set(new Set());
  }

  onConfirm(): void {
    if (!this.canConfirm()) return;
    const type = this.selectedReportType();
    if (!isDefined(type)) return;
    const cols = Array.from(this.selectedColumns());
    const allCols = this.availableColumns();
    const categories = [
      ...new Set(
        allCols.filter((c) => cols.includes(c.key)).map((c) => c.category),
      ),
    ];
    this.reportConfigSelected.emit({
      reportType: type,
      outputFormat: this.outputFormat(),
      includeAiAnalysis: false,
      columns: cols,
      columnCategories: categories,
    });
  }
}
