import { Component, input, output, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ButtonModule } from 'primeng/button';

import {
  InlineDatePickerComponent,
  DateRangeSelection,
} from '../inline-date-picker/inline-date-picker.component';
import {
  InlineVehicleSelectorComponent,
  Vehicle,
  VehicleSelectionResult,
} from '../inline-vehicle-selector/inline-vehicle-selector.component';
import { SelectableGroup } from '../../models/chat.interface';

export interface DateAndVehicleSelection {
  dateRange: DateRangeSelection;
  vehicles: Vehicle[];
  groups: SelectableGroup[];
}

@Component({
  selector: 'app-inline-date-vehicle-selector',
  imports: [
    CommonModule,
    ButtonModule,
    InlineDatePickerComponent,
    InlineVehicleSelectorComponent,
  ],
  templateUrl: './inline-date-vehicle-selector.component.html',
  styleUrl: './inline-date-vehicle-selector.component.scss',
})
export class InlineDateVehicleSelectorComponent {
  // Inputs
  vehicles = input<Vehicle[]>([]);
  assetGroups = input<SelectableGroup[]>([]);
  costCenters = input<SelectableGroup[]>([]);
  minDate = input<Date>(
    new Date(new Date().setFullYear(new Date().getFullYear() - 1)),
  );
  maxDate = input<Date>(new Date());

  // Outputs
  selectionConfirmed = output<DateAndVehicleSelection>();

  // State
  dateRange = signal<DateRangeSelection | null>(null);
  selectedVehicles = signal<Vehicle[]>([]);
  selectedGroups = signal<SelectableGroup[]>([]);

  readonly canConfirm = computed(
    () => this.dateRange() !== null && this.selectedVehicles().length > 0,
  );

  onVehicleSelectionChanged(result: VehicleSelectionResult): void {
    this.selectedVehicles.set(result.vehicles);
    this.selectedGroups.set(result.groups);
  }

  onConfirm(): void {
    const range = this.dateRange();
    const vehicles = this.selectedVehicles();
    if (range && vehicles.length > 0) {
      this.selectionConfirmed.emit({
        dateRange: range,
        vehicles,
        groups: this.selectedGroups(),
      });
    }
  }
}
