export function resolveDatePreset(
  preset: string,
): { startDate: Date; endDate: Date } | null {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  let startDate: Date;
  let endDate: Date;

  switch (preset) {
    case 'today':
      startDate = new Date(today);
      endDate = new Date(today);
      endDate.setHours(23, 59, 59, 999);
      break;
    case 'yesterday':
      startDate = new Date(today);
      startDate.setDate(startDate.getDate() - 1);
      endDate = new Date(startDate);
      endDate.setHours(23, 59, 59, 999);
      break;
    case 'last7':
      endDate = new Date(today);
      endDate.setHours(23, 59, 59, 999);
      startDate = new Date(today);
      startDate.setDate(startDate.getDate() - 6);
      break;
    case 'thisMonth':
      startDate = new Date(today.getFullYear(), today.getMonth(), 1);
      endDate = new Date(today);
      endDate.setHours(23, 59, 59, 999);
      break;
    case 'lastMonth':
      startDate = new Date(today.getFullYear(), today.getMonth() - 1, 1);
      endDate = new Date(today.getFullYear(), today.getMonth(), 0);
      endDate.setHours(23, 59, 59, 999);
      break;
    default:
      return null;
  }

  return { startDate, endDate };
}

export function buildLegacyAnalyticsResponse(
  data: unknown,
  vehicleCount: number,
  dateRangeLabel: string,
): AnalyticsResponse {
  const legacyData = data as {
    response?: { summary?: string; request_id?: string };
  };
  const summary =
    safeStringify(legacyData.response?.summary) ||
    'Analysis completed successfully';
  const timestamp = new Date().toISOString();
  const requestId = legacyData.response?.request_id ?? `req_${Date.now()}`;

  return {
    response: {
      request_id: requestId,
      timestamp: timestamp,
      summary: summary,
      layout: {
        type: 'dashboard',
        grid: {
          columns: 12,
          rows: 'auto',
          gap: 16,
        },
        sections: [
          {
            id: 'main-summary',
            title: 'Report Summary',
            position: {
              row: 1,
              col: 1,
              colSpan: 12,
            },
            blocks: ['summary-block-1'],
          },
        ],
      },
      blocks: [
        {
          block_id: 'summary-block-1',
          block_type: 'summary',
          priority: 1,
          content: {
            title: 'Fleet Analysis Report',
            narrative: summary,
            highlights: [
              {
                label: 'Vehicles Analyzed',
                value: vehicleCount,
                severity: 'neutral',
              },
              {
                label: 'Analysis Period',
                value: dateRangeLabel,
                severity: 'neutral',
              },
              {
                label: 'Report Status',
                value: 'Complete',
                severity: 'good',
              },
            ],
          },
          visual: {
            theme: 'primary',
            elevation: 1,
          },
        },
      ],
      metadata: {
        generated_at: new Date().toISOString(),
        model_used: 'legacy',
        processing_time_ms: 1000,
        analysis_type: 'fleet_overview',
        data_quality: 'good',
      },
    },
  };
}
