import { Component, Input } from '@angular/core';
import { CommonModule } from '@angular/common';
import {
  RecommendationBlock,
  Recommendation,
} from '../../models/analytics-dashboard.interface';

@Component({
  selector: 'app-recommendation-block',
  imports: [CommonModule],
  templateUrl: './recommendation-block.component.html',
  styleUrls: ['./recommendation-block.component.scss'],
})
export class RecommendationBlockComponent {
  @Input() block!: RecommendationBlock;

  getBlockClasses(): string[] {
    const classes: string[] = [];

    if (this.block.visual?.theme) {
      classes.push(`theme-${this.block.visual.theme}`);
    }

    return classes;
  }

  getPriorityClass(): string {
    return `priority-${this.block.content.priority}`;
  }

  getActionableCount(): number {
    return this.block.content.recommendations.filter((r) => r.actionable)
      .length;
  }

  trackByRec(index: number, rec: Recommendation): string {
    return rec.id;
  }
}
