import { Injectable, computed, effect, inject, signal } from '@angular/core';
import {
  DataTypeOption,
  DEFAULT_DATA_TYPE_OPTIONS,
} from '../models/analytical-report.types';
import { AnalyticalReportAssetsStore } from './assets.store';
import { AnalyticalReportDateStore } from './date.store';

@Injectable()
export class AnalyticalReportQueryStore {
  private readonly assetsStore = inject(AnalyticalReportAssetsStore);
  private readonly dateStore = inject(AnalyticalReportDateStore);

  private readonly _currentQuery = signal<string>('');
  private readonly _currentConfidence = signal<number>(0);
  private readonly _selectedDataTypesList = signal<string[]>([]);
  private readonly _dataTypeOptions = signal<DataTypeOption[]>([
    ...DEFAULT_DATA_TYPE_OPTIONS,
  ]);
  private readonly _analyzePerDay = signal<boolean>(false);
  private readonly _analyzePerVehicle = signal<boolean>(false);
  private readonly _lastReportQuery = signal<string>('');

  readonly currentQuery = this._currentQuery.asReadonly();
  readonly currentConfidence = this._currentConfidence.asReadonly();
  readonly selectedDataTypesList = this._selectedDataTypesList.asReadonly();
  readonly dataTypeOptions = this._dataTypeOptions.asReadonly();
  readonly analyzePerDay = this._analyzePerDay.asReadonly();
  readonly analyzePerVehicle = this._analyzePerVehicle.asReadonly();
  readonly lastReportQuery = this._lastReportQuery.asReadonly();

  readonly shouldDisableTelemetry = computed(
    () =>
      this.assetsStore.isMultipleVehiclesSelected() &&
      this.dateStore.isDateRangeGreaterThan2Days(),
  );

  readonly selectedDataTypes = computed(() =>
    this._dataTypeOptions()
      .filter((o) => o.selected)
      .map((o) => o.value),
  );

  readonly analysisBreakdownText = computed(() => {
    const parts: string[] = [];
    if (this._analyzePerDay() && this.dateStore.canAnalyzePerDay()) {
      parts.push('broken down by day');
    }
    if (this._analyzePerVehicle() && this.assetsStore.canAnalyzePerVehicle()) {
      parts.push('broken down by vehicle');
    }
    if (parts.length === 0) return '';
    return ` Please provide the analysis ${parts.join(' and ')}.`;
  });

  constructor() {
    effect(() => {
      if (this.shouldDisableTelemetry()) {
        this._dataTypeOptions.update((opts) =>
          opts.map((o) => ({
            ...o,
            selected: o.value === 'telemetry' ? false : o.selected,
          })),
        );
      }
    });
  }

  setCurrentQuery(query: string): void {
    this._currentQuery.set(query);
  }

  setCurrentConfidence(confidence: number): void {
    this._currentConfidence.set(confidence);
  }

  setSelectedDataTypesList(types: string[]): void {
    this._selectedDataTypesList.set(types);
  }

  setDataTypeOptions(options: DataTypeOption[]): void {
    this._dataTypeOptions.set(options);
  }

  updateDataTypeOptions(
    updater: (opts: DataTypeOption[]) => DataTypeOption[],
  ): void {
    this._dataTypeOptions.update(updater);
  }

  setAnalyzePerDay(value: boolean): void {
    this._analyzePerDay.set(value);
  }

  setAnalyzePerVehicle(value: boolean): void {
    this._analyzePerVehicle.set(value);
  }

  setLastReportQuery(query: string): void {
    this._lastReportQuery.set(query);
  }

  reset(): void {
    this._currentQuery.set('');
    this._currentConfidence.set(0);
    this._selectedDataTypesList.set([]);
    this._dataTypeOptions.set([...DEFAULT_DATA_TYPE_OPTIONS]);
    this._analyzePerDay.set(false);
    this._analyzePerVehicle.set(false);
    this._lastReportQuery.set('');
  }
}
