  private readonly apiUrlService = inject(ApiUrlService);

  private readonly chatApiBaseUrl = signal(
    this.apiUrlService.getCurrentApiUrl(),
  );

  // ============================================================================
  // State Signals
  // ============================================================================

  private readonly _isGenerating = signal(false);
  private readonly _generationProgress = signal('');
  private readonly _error = signal<string | null>(null);

  readonly isGenerating = this._isGenerating.asReadonly();
  readonly generationProgress = this._generationProgress.asReadonly();
  readonly error = this._error.asReadonly();

  // ============================================================================
  // Report Generation
  // ============================================================================

  async generateReport(
    request: ReportGenerationRequest,
  ): Promise<ReportGenerationResponse | null> {
    this._isGenerating.set(true);
    this._error.set(null);
    this._generationProgress.set('Generating report...');

    try {
      const response = await firstValueFrom(
        this.http.post<ReportGenerationResponse>(
          `${this.chatApiBaseUrl()}/generate-report`,
          {
            ...request,
            key_auth_token: this.authTokenManagerService.getAccessToken() ?? '',
            key_base_url: this.apiUrlService.getCurrentApiUrl(),
          },
        ),
      );
      return response;
    } catch (err) {
      this._error.set(
        err instanceof Error ? err.message : 'Report generation failed',
      );
      return null;
    } finally {
      this._isGenerating.set(false);
      this._generationProgress.set('');
    }
  }

  // ============================================================================
  // File Download
  // ============================================================================

  downloadReportFile(response: ReportGenerationResponse): void {
    const { data, filename, content_type } = response.report_file;
    const binary = atob(data);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) {
      bytes[i] = binary.charCodeAt(i);
    }
    const blob = new Blob([bytes], { type: content_type });
    const url = URL.createObjectURL(blob);
    const anchor = document.createElement('a');
    anchor.href = url;
    anchor.download = filename;
    anchor.click();
    URL.revokeObjectURL(url);
  }

  // ============================================================================
  // Schedule Methods
  // ============================================================================

  async createSchedule(
    conversationId: string,
    reportConfig: ReportGenerationRequest,
    schedule: ScheduleConfig,
  ): Promise<void> {
    try {
      await firstValueFrom(
        this.http.post<void>(`${this.chatApiBaseUrl()}/schedule-report`, {
          conversation_id: conversationId,
          report_config: reportConfig,
          schedule,
          auth_token: this.authTokenManagerService.getAccessToken() ?? '',
          base_url: this.apiUrlService.getCurrentApiUrl(),
        }),
      );
    } catch (err) {
      this._error.set(
        err instanceof Error ? err.message : 'Failed to create schedule',
      );
    }
  }

  async listSchedules(): Promise<ScheduleItem[]> {
    try {
      const response = await firstValueFrom(
        this.http.get<{ schedules: ScheduleItem[]; count: number }>(
          `${this.chatApiBaseUrl()}/scheduled-reports`,
          {
            headers: {
              'x-access-token':
                this.authTokenManagerService.getAccessToken() ?? '',
              'x-base-url': this.apiUrlService.getCurrentApiUrl(),
            },
          },
        ),
      );
      return response.schedules ?? [];
    } catch (err) {
      this._error.set(
        err instanceof Error ? err.message : 'Failed to load schedules',
      );
      return [];
    }
  }

  async deleteSchedule(scheduleId: string): Promise<void> {
    try {
      await firstValueFrom(
        this.http.delete<void>(
          `${this.chatApiBaseUrl()}/scheduled-reports/${scheduleId}`,
          {
            headers: {
              'x-access-token':
                this.authTokenManagerService.getAccessToken() ?? '',
              'x-base-url': this.apiUrlService.getCurrentApiUrl(),
            },
          },
        ),
      );
    } catch (err) {
      this._error.set(
        err instanceof Error ? err.message : 'Failed to delete schedule',
      );
    }
  }

