import {
  Component,
  input,
  output,
  signal,
  computed,
  effect,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { IconFieldModule } from 'primeng/iconfield';
import { InputIconModule } from 'primeng/inputicon';
import { CheckboxModule } from 'primeng/checkbox';
import { AccordionModule } from 'primeng/accordion';
import { SelectableGroup } from '../../models/chat.interface';

export interface Vehicle {
  id: string;
  name: string;
  registration?: string;
}

export interface VehicleSelectionResult {
  vehicles: Vehicle[];
  groups: SelectableGroup[];
}

@Component({
  selector: 'app-inline-vehicle-selector',
  imports: [
    CommonModule,
    FormsModule,
    ButtonModule,
    InputTextModule,
    IconFieldModule,
    InputIconModule,
    CheckboxModule,
    AccordionModule,
  ],
  templateUrl: './inline-vehicle-selector.component.html',
  styleUrl: './inline-vehicle-selector.component.scss',
})
export class InlineVehicleSelectorComponent {
  // Inputs
  vehicles = input<Vehicle[]>([]);
  assetGroups = input<SelectableGroup[]>([]);
  costCenters = input<SelectableGroup[]>([]);
  initialSelection = input<string[]>([]);
  maxSelection = input<number | null>(null);
  hideConfirm = input<boolean>(false);

  // Outputs
  vehiclesSelected = output<VehicleSelectionResult>();
  selectionChanged = output<VehicleSelectionResult>();

  // Local state
  searchTerm = signal<string>('');
  private _selectedIds = signal<Set<string>>(new Set());
  expandedGroupIds = signal<Set<string>>(
    new Set(['__asset_groups__', '__cost_centers__']),
  );
  // Accordion open sections: 'assetGroups' | 'costCenters' | 'individuals'
  accordionValue = signal<string[]>(['assetGroups', 'costCenters']);

  // --- Computed: filtered sections based on search term ---

  readonly filteredAssetGroups = computed(() => {
    const term = this.searchTerm().toLowerCase();
    if (!term) return this.assetGroups();
    return this.assetGroups().filter((g) =>
      g.name.toLowerCase().includes(term),
    );
  });

  readonly filteredCostCenters = computed(() => {
    const term = this.searchTerm().toLowerCase();
    if (!term) return this.costCenters();
    return this.costCenters().filter((g) =>
      g.name.toLowerCase().includes(term),
    );
  });

  readonly filteredVehicles = computed(() => {
    const term = this.searchTerm().toLowerCase();
    const allVehicles = this.vehicles();
    if (!term) return allVehicles;
    return allVehicles.filter(
      (v) =>
        v.name.toLowerCase().includes(term) ||
        (v.registration?.toLowerCase()?.includes(term) ?? false),
    );
  });

  // --- Selection state ---

  readonly selectedIds = this._selectedIds.asReadonly();

  readonly selectedCount = computed(() => this._selectedIds().size);

  readonly canConfirm = computed(() => this._selectedIds().size > 0);

  readonly hasAssetGroupSelection = computed(() =>
    this.assetGroups().some((g) => this.groupSelectionState(g) !== 'none'),
  );

  readonly hasCostCenterSelection = computed(() =>
    this.costCenters().some((g) => this.groupSelectionState(g) !== 'none'),
  );

  readonly hasIndividualSelection = computed(() =>
    this.vehicles().some((v) => this._selectedIds().has(v.id)),
  );

  readonly allIndividualsSelected = computed(() => {
    const vehicles = this.vehicles();
    const selected = this._selectedIds();
    return vehicles.length > 0 && vehicles.every((v) => selected.has(v.id));
  });

  // --- Group selection state helpers ---

  groupSelectionState(group: SelectableGroup): 'all' | 'none' | 'partial' {
    const selected = this._selectedIds();
    const inGroup = group.assetIds.filter((id) => selected.has(id)).length;
    if (inGroup === 0) return 'none';
    if (inGroup === group.assetIds.length) return 'all';
    return 'partial';
  }

  isGroupChecked(group: SelectableGroup): boolean {
    return this.groupSelectionState(group) === 'all';
  }

  isGroupIndeterminate(group: SelectableGroup): boolean {
    return this.groupSelectionState(group) === 'partial';
  }

  isSelected(id: string): boolean {
    return this._selectedIds().has(id);
  }

  // --- Currently selected groups (for output) ---

  private readonly _selectedGroups = computed((): SelectableGroup[] => {
    const selected = this._selectedIds();
    const allGroups = [...this.assetGroups(), ...this.costCenters()];
    return allGroups.filter(
      (g) =>
        g.assetIds.length > 0 && g.assetIds.every((id) => selected.has(id)),
    );
  });

  private readonly _selectedVehicles = computed((): Vehicle[] => {
    const selected = this._selectedIds();
    return this.vehicles().filter((v) => selected.has(v.id));
  });

  readonly summaryText = computed(() => {
    const count = this.selectedCount();
    const groups = this._selectedGroups();
    const groupCount = groups.filter((g) => g.type === 'asset_group').length;
    const ccCount = groups.filter((g) => g.type === 'cost_center').length;

    if (count === 0) return null;

    const parts: string[] = [
      `${count} asset${count === 1 ? '' : 's'} selected`,
    ];
    const tagParts: string[] = [];
    if (groupCount > 0)
      tagParts.push(`${groupCount} group${groupCount === 1 ? '' : 's'}`);
    if (ccCount > 0)
      tagParts.push(`${ccCount} cost center${ccCount === 1 ? '' : 's'}`);
    if (tagParts.length > 0) parts.push(`(${tagParts.join(', ')})`);
    return parts.join(' ');
  });

  constructor() {
    // Seed selection from initialSelection input — runs only once on first non-empty value
    let seeded = false;
    effect(() => {
      const initial = this.initialSelection();
      if (!seeded && initial.length > 0) {
        seeded = true;
        this._selectedIds.set(new Set(initial));
      }
    });

    effect(() => {
      const result: VehicleSelectionResult = {
        vehicles: this._selectedVehicles(),
        groups: this._selectedGroups(),
      };
      this.selectionChanged.emit(result);
    });
  }

  // --- Toggle actions ---

  toggleGroup(group: SelectableGroup): void {
    const state = this.groupSelectionState(group);
    this._selectedIds.update((ids) => {
      const next = new Set(ids);
      if (state === 'all') {
        group.assetIds.forEach((id) => next.delete(id));
      } else {
        group.assetIds.forEach((id) => next.add(id));
      }
      return next;
    });
  }

  toggleVehicle(vehicle: Vehicle): void {
    this._selectedIds.update((ids) => {
      const next = new Set(ids);
      if (next.has(vehicle.id)) {
        next.delete(vehicle.id);
      } else {
        next.add(vehicle.id);
      }
      return next;
    });
  }

  toggleGroupExpanded(groupId: string): void {
    this.expandedGroupIds.update((ids) => {
      const next = new Set(ids);
      if (next.has(groupId)) {
        next.delete(groupId);
      } else {
        next.add(groupId);
      }
      return next;
    });
  }

  isGroupExpanded(groupId: string): boolean {
    return this.expandedGroupIds().has(groupId);
  }

  selectAll(): void {
    const allIds = this.vehicles().map((v) => v.id);
    this._selectedIds.set(new Set(allIds));
  }

  clearAll(): void {
    this._selectedIds.set(new Set());
  }

  onConfirm(): void {
    if (this.canConfirm()) {
      this.vehiclesSelected.emit({
        vehicles: this._selectedVehicles(),
        groups: this._selectedGroups(),
      });
    }
  }

  // Vehicle IDs in a group that match the current search
  groupVehicles(group: SelectableGroup): Vehicle[] {
    const term = this.searchTerm().toLowerCase();
    return this.vehicles()
      .filter((v) => group.assetIds.includes(v.id))
      .filter(
        (v) =>
          !term ||
          v.name.toLowerCase().includes(term) ||
          (v.registration?.toLowerCase()?.includes(term) ?? false),
      );
  }
}
