import { Injectable, computed, inject, signal } from '@angular/core';
import { ConversationSummary } from '../../../../../core/interfaces/conversation.interface';
import { HeaderSummary } from '../chat/components/chat-summary-header/chat-summary-header.component';
import { AnalyticalReportAssetsStore } from './assets.store';
import { AnalyticalReportDateStore } from './date.store';
import { AnalyticalReportQueryStore } from './query.store';

@Injectable()
export class AnalyticalReportSessionStore {
  private readonly assetsStore = inject(AnalyticalReportAssetsStore);
  private readonly dateStore = inject(AnalyticalReportDateStore);
  private readonly queryStore = inject(AnalyticalReportQueryStore);

  private readonly _selectedConversationForReports =
    signal<ConversationSummary | null>(null);
  private readonly _viewingExistingSession = signal<boolean>(false);

  readonly selectedConversationForReports =
    this._selectedConversationForReports.asReadonly();
  readonly viewingExistingSession = this._viewingExistingSession.asReadonly();

  readonly headerSummary = computed((): HeaderSummary => {
    const start = this.dateStore.startDate();
    const end = this.dateStore.endDate();
    const assetIds = this.assetsStore.selectedAssetIds();
    const allAssets = this.assetsStore.assets();
    const contextNames = this.assetsStore.contextVehicleNames();

    const vehicleNames = assetIds
      .map((id) => {
        const asset = allAssets.find((a) => a.value === id);
        return asset?.label ?? contextNames[id] ?? '';
      })
      .filter((name) => name.length > 0);

    return {
      dateRange: start && end ? { start, end } : null,
      vehicleCount: assetIds.length,
      vehicleNames,
      dataTypes: this.queryStore.selectedDataTypesList(),
      queryConfidence: this.queryStore.currentConfidence(),
      currentQuery: this.queryStore.currentQuery(),
    };
  });

  setSelectedConversationForReports(
    conversation: ConversationSummary | null,
  ): void {
    this._selectedConversationForReports.set(conversation);
  }

  setViewingExistingSession(viewing: boolean): void {
    this._viewingExistingSession.set(viewing);
  }

  reset(): void {
    this._viewingExistingSession.set(false);
  }
}
