import { Component, input, output, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ButtonModule } from 'primeng/button';
import { CheckboxModule } from 'primeng/checkbox';
import { ChipModule } from 'primeng/chip';
import { TooltipModule } from 'primeng/tooltip';
import { FormsModule } from '@angular/forms';

import {
  ChatMessage,
  SuggestedAction,
  VehicleOption,
} from '../../models/chat.interface';
import { AnalyticsSnapshotMeta } from '../../../../../../../core/interfaces/conversation.interface';
import { FormatMarkdownPipe } from '../../pipes/format-markdown.pipe';
import {
  InlineDatePickerComponent,
  DateRangeSelection,
} from '../inline-date-picker/inline-date-picker.component';
import {
  InlineVehicleSelectorComponent,
  Vehicle,
  VehicleSelectionResult,
} from '../inline-vehicle-selector/inline-vehicle-selector.component';
import { InlineDataTypeSelectorComponent } from '../inline-data-type-selector/inline-data-type-selector.component';
import {
  InlineReportConfigComponent,
  ReportConfigSelection,
} from '../inline-report-config/inline-report-config.component';
import {
  InlineScheduleConfigComponent,
  ScheduleConfigSelection,
} from '../inline-schedule-config/inline-schedule-config.component';
import {
  InlineDateVehicleSelectorComponent,
  DateAndVehicleSelection,
} from '../inline-date-vehicle-selector/inline-date-vehicle-selector.component';
import { SelectableGroup } from '../../models/chat.interface';
import {
  ReportGenerationRequest,
  ReportType,
} from '../../../../../../../core/interfaces/report-generation.interface';
import { TimeAgoPipe } from '../../../../../../../shared/pipes/time-ago.pipe';
import { InlineReportTypeSelectorComponent } from '../inline-report-type-selector/inline-report-type-selector.component';

// Data type values for multi-select detection
const DATA_TYPE_VALUES = new Set(['trips', 'events', 'telemetry', 'alerts']);

@Component({
  selector: 'app-chat-message',
  imports: [
    CommonModule,
    ButtonModule,
    CheckboxModule,
    ChipModule,
    TooltipModule,
    FormsModule,
    FormatMarkdownPipe,
    InlineDatePickerComponent,
    InlineVehicleSelectorComponent,
    InlineDataTypeSelectorComponent,
    InlineReportConfigComponent,
    InlineScheduleConfigComponent,
    InlineDateVehicleSelectorComponent,
    InlineReportTypeSelectorComponent,
    TimeAgoPipe,
  ],
  templateUrl: './chat-message.component.html',
  styleUrl: './chat-message.component.scss',
})
export class ChatMessageComponent {
  // Inputs
  message = input.required<ChatMessage>();
  isDisabled = input<boolean>(false); // Disable interactions (e.g., during data collection)
  isLastMessage = input<boolean>(false);

  // Outputs
  actionSelected = output<SuggestedAction>();
  multiActionsSelected = output<SuggestedAction[]>();
  dateRangeSelected = output<DateRangeSelection>();
  availableAssetGroups = input<SelectableGroup[]>([]);
  availableCostCenters = input<SelectableGroup[]>([]);

  dateAndVehicleSelected = output<DateAndVehicleSelection>();
  vehiclesSelected = output<VehicleSelectionResult>();
  dataTypesSelected = output<string[]>();
  reportConfigSelected = output<ReportConfigSelection>();
  scheduleConfigSelected = output<ScheduleConfigSelection>();
  viewAnalyticsSnapshot = output<AnalyticsSnapshotMeta>();
  reportTypesConfirmed = output<ReportType[]>();

  // ID of the snapshot currently being loaded (controlled by parent)
  loadingSnapshotId = input<string | null>(null);

  // Local state for multi-select
  selectedActionIds = signal<Set<string>>(new Set());

  // Derived: is this message's snapshot currently loading?
  readonly snapshotLoading = computed(() => {
    const snap = this.analyticsSnapshotFromMessage();
    return snap !== null && this.loadingSnapshotId() === snap.snapshot_id;
  });

  // Computed properties
  readonly isUser = computed(() => this.message().sender === 'user');
  readonly isAssistant = computed(() => this.message().sender === 'assistant');
  readonly isSystem = computed(() => this.message().sender === 'system');

  readonly formattedTime = computed(() =>
    this.formatTime(this.message().timestamp),
  );

  readonly suggestedActions = computed(
    () => this.message().metadata?.suggestedActions ?? [],
  );
  readonly hasSuggestedActions = computed(
    () => this.suggestedActions().length > 0,
  );

  // Receipt chips: actions the user selected (shown on user messages)
  readonly receiptActions = computed(
    () => this.message().metadata?.selectedActions ?? [],
  );
  readonly hasReceiptActions = computed(() => this.receiptActions().length > 0);

  // Lock suggestions when this assistant message is no longer the last message
  readonly suggestionsLocked = computed(
    () =>
      this.isAssistant() && !this.isLastMessage() && this.hasSuggestedActions(),
  );

  // Interactive type computed properties
  readonly interactiveType = computed(
    () => this.message().metadata?.interactiveType,
  );
  readonly hasInteractiveComponent = computed(() => !!this.interactiveType());
  readonly isDatePicker = computed(
    () => this.interactiveType() === 'date_picker',
  );
  readonly isDateAndVehicleSelector = computed(
    () => this.interactiveType() === 'date_and_vehicle_selector',
  );
  readonly isVehicleSelector = computed(
    () => this.interactiveType() === 'vehicle_selector',
  );
  readonly isDataTypeSelector = computed(
    () => this.interactiveType() === 'data_type_selector',
  );
  readonly isReportConfig = computed(
    () => this.interactiveType() === 'report_config',
  );
  readonly isScheduleConfig = computed(
    () => this.interactiveType() === 'schedule_config',
  );
  readonly isReportFile = computed(
    () => this.interactiveType() === 'report_file',
  );
  readonly isAnalyticsSnapshot = computed(
    () => this.interactiveType() === 'analytics_snapshot',
  );
  readonly isScheduledReport = computed(
    () => this.interactiveType() === 'scheduled_report',
  );
  readonly isReportTypeSelector = computed(
    () => this.interactiveType() === 'report_type_selector',
  );
  readonly isReportFileGroup = computed(
    () => this.interactiveType() === 'report_file_group',
  );

  readonly reportFileFromMessage = computed(
    () => this.message().metadata?.reportFile ?? null,
  );

  readonly reportFilesFromMessage = computed(
    () => this.message().metadata?.reportFiles ?? [],
  );

  readonly scheduledReportFromMessage = computed(
    () => this.message().metadata?.scheduledReport ?? null,
  );

  readonly analyticsSnapshotFromMessage = computed(
    (): AnalyticsSnapshotMeta | null =>
      this.message().metadata?.analyticsSnapshot ?? null,
  );

  readonly reportConfigFromMessage = computed(
    (): ReportGenerationRequest | null =>
      this.message().metadata?.reportConfig ?? null,
  );

  // Available vehicles for vehicle selector
  readonly availableVehicles = computed((): Vehicle[] => {
    const vehicles = this.message().metadata?.availableVehicles ?? [];
    return vehicles.map((v: VehicleOption) => ({
      id: v.id,
      name: v.name,
      registration: undefined,
    }));
  });

  // Selected data types from message metadata (for persistence)
  readonly selectedDataTypesFromMessage = computed((): string[] => {
    return this.message().metadata?.selectedDataTypes ?? [];
  });

  // Check if multi-select mode should be enabled
  // Now enabled for all suggestions with 2+ options
  readonly isMultiSelectMode = computed(() => {
    const actions = this.suggestedActions();
    return actions.length >= 2;
  });

  // Check if all suggestions are data type related
  readonly isDataTypeMultiSelect = computed(() => {
    const actions = this.suggestedActions();
    return (
      actions.length >= 2 &&
      actions.every((action) =>
        DATA_TYPE_VALUES.has(action.value.toLowerCase()),
      )
    );
  });

  // Check if an action is selected
  isActionSelected(actionId: string): boolean {
    return this.selectedActionIds().has(actionId);
  }

  // Get selected actions
  readonly selectedActions = computed(() => {
    const ids = this.selectedActionIds();
    return this.suggestedActions().filter((action) => ids.has(action.id));
  });

  // Check if any actions are selected
  readonly hasSelectedActions = computed(
    () => this.selectedActionIds().size > 0,
  );

  readonly statusIcon = computed(() => {
    switch (this.message().status) {
      case 'sending':
        return 'pi pi-clock';
      case 'sent':
        return 'pi pi-check';
      case 'delivered':
        return 'pi pi-check-circle';
      case 'error':
        return 'pi pi-exclamation-circle';
      default:
        return '';
    }
  });

  readonly statusClass = computed(() => {
    return this.message().status === 'error' ? 'text-red-500' : 'text-blue-400';
  });

  onActionClick(action: SuggestedAction): void {
    this.actionSelected.emit(action);
  }

  // Toggle action selection for multi-select mode
  toggleActionSelection(actionId: string): void {
    this.selectedActionIds.update((current) => {
      const newSet = new Set(current);
      if (newSet.has(actionId)) {
        newSet.delete(actionId);
      } else {
        newSet.add(actionId);
      }
      return newSet;
    });
  }

  // Select all data type actions
  selectAllActions(): void {
    const allIds = this.suggestedActions().map((a) => a.id);
    this.selectedActionIds.set(new Set(allIds));
  }

  // Submit selected actions
  submitSelectedActions(): void {
    const selected = this.selectedActions();
    if (selected.length > 0) {
      this.multiActionsSelected.emit(selected);
      // Clear selection after submission
      this.selectedActionIds.set(new Set());
    }
  }

  // Handler for inline date picker
  onDateRangeSelected(dateRange: DateRangeSelection): void {
    this.dateRangeSelected.emit(dateRange);
  }

  // Handler for combined date + vehicle selector
  onDateAndVehicleSelected(selection: DateAndVehicleSelection): void {
    this.dateAndVehicleSelected.emit(selection);
  }

  // Handler for inline vehicle selector
  onVehiclesSelected(result: VehicleSelectionResult): void {
    this.vehiclesSelected.emit(result);
  }

  // Handler for inline data type selector
  onDataTypesSelected(dataTypes: string[]): void {
    this.dataTypesSelected.emit(dataTypes);
  }

  // Handler for inline report config
  onReportConfigSelected(config: ReportConfigSelection): void {
    this.reportConfigSelected.emit(config);
  }

  // Handlers for inline schedule config
  onScheduleConfigSelected(config: ScheduleConfigSelection): void {
    this.scheduleConfigSelected.emit(config);
  }

  onScheduleConfigCancelled(): void {
    // parent can handle or ignore
  }

  // Receipt: report types confirmed (shown after selector is locked)
  readonly selectedReportTypesFromMessage = computed(
    (): ReportType[] => this.message().metadata?.selectedReportTypes ?? [],
  );
  readonly hasSelectedReportTypes = computed(
    () => this.selectedReportTypesFromMessage().length > 0,
  );

  onReportTypesConfirmed(types: ReportType[]): void {
    this.reportTypesConfirmed.emit(types);
  }

  onViewAnalyticsSnapshot(): void {
    const snap = this.analyticsSnapshotFromMessage();
    if (snap) {
      this.viewAnalyticsSnapshot.emit(snap);
    }
  }

  formatFileSize(bytes: number): string {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  }

  private formatTime(date: Date): string {
    return date.toLocaleTimeString('en-US', {
      hour: '2-digit',
      minute: '2-digit',
      hour12: false,
    });
  }
}
