import { Component, Input } from '@angular/core';
import { CommonModule } from '@angular/common';
import {
  AlertBlock,
  AffectedEntity,
} from '../../models/analytics-dashboard.interface';

@Component({
  selector: 'app-alert-block',
  imports: [CommonModule],
  templateUrl: './alert-block.component.html',
  styleUrl: './alert-block.component.scss',
})
export class AlertBlockComponent {
  @Input() block!: AlertBlock;

  trackByEntity(index: number, entity: AffectedEntity): string {
    return entity.id;
  }

  getAlertClasses(): string[] {
    return [`severity-${this.block.content.severity}`];
  }

  getSeverityIconClass(): string {
    return `icon-${this.block.content.severity}`;
  }

  getSeverityIcon(): string {
    switch (this.block.content.severity) {
      case 'critical':
        return '⚠';
      case 'warning':
        return '⚡';
      case 'info':
        return 'ℹ';
      default:
        return '•';
    }
  }

  getEntityTypeLabel(): string {
    const entities = this.block.content.affected_entities;
    if (entities.length === 0) return '';

    const types = [...new Set(entities.map((e) => e.type))];
    if (types.length === 1) {
      return types[0] + (entities.length > 1 ? 's' : '');
    }
    return 'entities';
  }

  getEntityIcon(type: string): string {
    switch (type) {
      case 'vehicle':
        return '🚗';
      case 'driver':
        return '👤';
      case 'geofence':
        return '📍';
      default:
        return '•';
    }
  }

  formatTimestamp(timestamp: string): string {
    try {
      const date = new Date(timestamp);
      const now = new Date();
      const diffMs = now.getTime() - date.getTime();
      const diffMins = Math.floor(diffMs / 60000);
      const diffHours = Math.floor(diffMins / 60);
      const diffDays = Math.floor(diffHours / 24);

      if (diffMins < 1) {
        return 'Just now';
      } else if (diffMins < 60) {
        return `${diffMins}m ago`;
      } else if (diffHours < 24) {
        return `${diffHours}h ago`;
      } else if (diffDays < 7) {
        return `${diffDays}d ago`;
      } else {
        return date.toLocaleDateString('en-ZA', {
          month: 'short',
          day: 'numeric',
          hour: '2-digit',
          minute: '2-digit',
        });
      }
    } catch {
      return timestamp;
    }
  }

  takeAction(): void {
    // Implement action logic here
  }

  dismissAlert(): void {
    // Implement dismiss logic here
  }
}
