import { Injectable } from '@angular/core';

@Injectable({ providedIn: 'root' })
export class ChatSoundService {
  private readonly soundsEnabled = false;

  private audioContext: AudioContext | null = null;

  private getContext(): AudioContext | null {
    if (!this.soundsEnabled) return null;
    try {
      if (!this.audioContext) {
        this.audioContext = new AudioContext();
      }
      return this.audioContext;
    } catch {
      return null;
    }
  }

  private playTone(
    frequency: number,
    startTime: number,
    duration: number,
    volume: number,
    type: OscillatorType = 'sine',
    ctx?: AudioContext,
  ): void {
    const context = ctx ?? this.getContext();
    if (!context) return;

    try {
      const oscillator = context.createOscillator();
      const gainNode = context.createGain();

      oscillator.connect(gainNode);
      gainNode.connect(context.destination);

      oscillator.type = type;
      oscillator.frequency.setValueAtTime(frequency, startTime);

      gainNode.gain.setValueAtTime(0, startTime);
      gainNode.gain.linearRampToValueAtTime(volume, startTime + 0.01);
      gainNode.gain.linearRampToValueAtTime(0, startTime + duration);

      oscillator.start(startTime);
      oscillator.stop(startTime + duration);
    } catch {
      // Silently swallow audio errors
    }
  }

  /** Single soft mid-tone blip — played when assistant starts typing */
  playAssistantTypingSound(): void {
    const ctx = this.getContext();
    if (!ctx) return;
    this.playTone(600, ctx.currentTime, 0.08, 0.08, 'sine', ctx);
  }

  /** Two ascending tones — played when a new assistant message arrives */
  playNewMessageSound(): void {
    const ctx = this.getContext();
    if (!ctx) return;
    const t = ctx.currentTime;
    this.playTone(880, t, 0.15, 0.1, 'sine', ctx);
    this.playTone(1100, t + 0.15, 0.15, 0.1, 'sine', ctx);
  }

  /** Quick high-to-low sweep — played when user sends a message */
  playSendMessageSound(): void {
    const ctx = this.getContext();
    if (!ctx) return;
    try {
      const oscillator = ctx.createOscillator();
      const gainNode = ctx.createGain();

      oscillator.connect(gainNode);
      gainNode.connect(ctx.destination);

      const t = ctx.currentTime;
      oscillator.type = 'sine';
      oscillator.frequency.setValueAtTime(1200, t);
      oscillator.frequency.linearRampToValueAtTime(800, t + 0.1);

      gainNode.gain.setValueAtTime(0, t);
      gainNode.gain.linearRampToValueAtTime(0.1, t + 0.01);
      gainNode.gain.linearRampToValueAtTime(0, t + 0.1);

      oscillator.start(t);
      oscillator.stop(t + 0.1);
    } catch {
      // Silently swallow audio errors
    }
  }

  /** Three ascending notes — played when session connects */
  playSessionStartSound(): void {
    const ctx = this.getContext();
    if (!ctx) return;
    const t = ctx.currentTime;
    const step = 0.12;
    this.playTone(440, t, step, 0.1, 'sine', ctx);
    this.playTone(550, t + step, step, 0.1, 'sine', ctx);
    this.playTone(660, t + step * 2, step, 0.1, 'sine', ctx);
  }

  /** Two tones low→high with smooth fade — played on generate report */
  playGenerateReportSound(): void {
    const ctx = this.getContext();
    if (!ctx) return;
    try {
      const t = ctx.currentTime;
      const notes = [
        { freq: 440, start: t },
        { freq: 880, start: t + 0.15 },
      ];
      for (const note of notes) {
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.type = 'sine';
        osc.frequency.setValueAtTime(note.freq, note.start);
        gain.gain.setValueAtTime(0, note.start);
        gain.gain.linearRampToValueAtTime(0.1, note.start + 0.01);
        gain.gain.linearRampToValueAtTime(0, note.start + 0.25);
        osc.start(note.start);
        osc.stop(note.start + 0.25);
      }
    } catch {
      // Silently swallow audio errors
    }
  }

  /** Three quick ascending tones with sustain — played when analytics loads */
  playAnalyticsCompleteSound(): void {
    const ctx = this.getContext();
    if (!ctx) return;
    const t = ctx.currentTime;
    const step = 0.08;
    this.playTone(660, t, step + 0.05, 0.1, 'sine', ctx);
    this.playTone(880, t + step, step + 0.05, 0.1, 'sine', ctx);
    this.playTone(1100, t + step * 2, step + 0.1, 0.1, 'sine', ctx);
  }

  /** Single low tone with downward sweep — played on error */
  playErrorSound(): void {
    const ctx = this.getContext();
    if (!ctx) return;
    try {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);

      const t = ctx.currentTime;
      osc.type = 'sine';
      osc.frequency.setValueAtTime(220, t);
      osc.frequency.linearRampToValueAtTime(150, t + 0.3);

      gain.gain.setValueAtTime(0, t);
      gain.gain.linearRampToValueAtTime(0.1, t + 0.01);
      gain.gain.linearRampToValueAtTime(0, t + 0.3);

      osc.start(t);
      osc.stop(t + 0.3);
    } catch {
      // Silently swallow audio errors
    }
  }
}
