import { Component, inject, output, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ButtonModule } from 'primeng/button';

import { ReportGenerationService } from '../../../../../../../core/services/report-generation.service';
import { ReportType } from '../../../../../../../core/interfaces/report-generation.interface';

@Component({
  selector: 'app-inline-report-type-selector',
  imports: [CommonModule, ButtonModule],
  templateUrl: './inline-report-type-selector.component.html',
  styleUrl: './inline-report-type-selector.component.scss',
})
export class InlineReportTypeSelectorComponent {
  private readonly reportGenerationService = inject(ReportGenerationService);

  // Output
  reportTypesConfirmed = output<ReportType[]>();

  // All available report types from service
  readonly reportTypes = this.reportGenerationService.getReportTypes();

  // Local state
  selectedIds = signal<Set<ReportType>>(new Set());

  // Computed
  readonly selectedCount = computed(() => this.selectedIds().size);
  readonly canConfirm = computed(() => this.selectedCount() > 0);
  readonly allSelected = computed(
    () =>
      this.reportTypes.length > 0 &&
      this.reportTypes.every((t) => this.selectedIds().has(t.report_type)),
  );

  isSelected(id: ReportType): boolean {
    return this.selectedIds().has(id);
  }

  toggleType(id: ReportType): void {
    const current = new Set(this.selectedIds());
    if (current.has(id)) {
      current.delete(id);
    } else {
      current.add(id);
    }
    this.selectedIds.set(current);
  }

  selectAll(): void {
    this.selectedIds.set(new Set(this.reportTypes.map((t) => t.report_type)));
  }

  clearAll(): void {
    this.selectedIds.set(new Set());
  }

  onConfirm(): void {
    const selected = Array.from(this.selectedIds());
    if (selected.length > 0) {
      this.reportTypesConfirmed.emit(selected);
    }
  }
}
