import {
  Component,
  input,
  output,
  signal,
  computed,
  effect,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { DatePickerModule } from 'primeng/datepicker';
import { ButtonModule } from 'primeng/button';

export interface DateRangeSelection {
  start: Date;
  end: Date;
}

@Component({
  selector: 'app-inline-date-picker',
  imports: [CommonModule, FormsModule, DatePickerModule, ButtonModule],
  templateUrl: './inline-date-picker.component.html',
  styleUrl: './inline-date-picker.component.scss',
})
export class InlineDatePickerComponent {
  // Inputs
  initialStart = input<Date | null>(null);
  initialEnd = input<Date | null>(null);
  hideConfirm = input<boolean>(false);
  minDate = input<Date>(
    new Date(new Date().setFullYear(new Date().getFullYear() - 1)),
  );
  maxDate = input<Date>(
    new Date(
      new Date().getFullYear(),
      new Date().getMonth(),
      new Date().getDate() + 1,
      0,
      0,
      0,
      0,
    ),
  );

  // Outputs
  dateRangeSelected = output<DateRangeSelection>();
  dateRangeChanged = output<DateRangeSelection | null>();

  // Local state
  startDate = signal<Date | null>(null);
  endDate = signal<Date | null>(null);
  selectedPreset = signal<number | null>(null);

  constructor() {
    effect(() => {
      const start = this.startDate();
      const end = this.endDate();
      this.dateRangeChanged.emit(
        start && end && start <= end ? { start, end } : null,
      );
    });
  }

  // Date presets
  readonly datePresets = [
    { label: 'Today', days: 0 },
    { label: 'Yesterday', days: 1 },
    { label: 'Last 7 days', days: 7 },
    { label: 'Last 30 days', days: 30 },
    { label: 'Last 90 days', days: 90 },
  ];

  readonly canConfirm = computed(() => {
    const start = this.startDate();
    const end = this.endDate();
    return start !== null && end !== null && start <= end;
  });

  readonly formattedRange = computed(() => {
    const start = this.startDate();
    const end = this.endDate();

    if (!start || !end) return '';

    const formatDate = (date: Date) => {
      return date.toLocaleDateString('en-US', {
        month: 'short',
        day: 'numeric',
        year: 'numeric',
      });
    };

    if (start.toDateString() === end.toDateString()) {
      return formatDate(start);
    }
    return `${formatDate(start)} - ${formatDate(end)}`;
  });

  selectPreset(days: number): void {
    const now = new Date();
    let start = now;
    let end = now;

    if (days === 0) {
      // Today: midnight to end-of-day
      start = new Date(
        now.getFullYear(),
        now.getMonth(),
        now.getDate(),
        0,
        0,
        0,
        0,
      );
      end = new Date(
        now.getFullYear(),
        now.getMonth(),
        now.getDate(),
        23,
        59,
        59,
        999,
      );
    } else if (days === 1) {
      // Yesterday: midnight to end-of-day
      const yesterday = new Date(now);
      yesterday.setDate(yesterday.getDate() - 1);
      start = new Date(
        yesterday.getFullYear(),
        yesterday.getMonth(),
        yesterday.getDate(),
        0,
        0,
        0,
        0,
      );
      end = new Date(
        yesterday.getFullYear(),
        yesterday.getMonth(),
        yesterday.getDate(),
        23,
        59,
        59,
        999,
      );
    } else {
      // Last N days: start at midnight N days ago, end at end-of-today
      start = new Date(
        now.getFullYear(),
        now.getMonth(),
        now.getDate() - days,
        0,
        0,
        0,
        0,
      );
      end = new Date(
        now.getFullYear(),
        now.getMonth(),
        now.getDate(),
        23,
        59,
        59,
        999,
      );
    }

    this.startDate.set(start);
    this.endDate.set(end);
    this.selectedPreset.set(days);
  }

  onConfirm(): void {
    const start = this.startDate();
    const end = this.endDate();
    if (start && end && start <= end) {
      this.dateRangeSelected.emit({ start, end });
    }
  }
}
