import { Injectable, inject } from '@angular/core';

import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { ReportGenerationService } from '../../../../../core/services/report-generation.service';
import {
  ReportGenerationRequest,
  ReportGenerationResponse,
  ReportType,
} from '../../../../../core/interfaces/report-generation.interface';
import { ReportConfigDrawerResult } from '../chat/components/report-config-drawer/report-config-drawer.component';
import { ConversationHistoryService } from '../../../../../core/services/conversation-history.service';
import { AnalyticalReportAssetsStore } from '../store/assets.store';
import { AnalyticalReportDateStore } from '../store/date.store';
import { AnalyticalReportQueryStore } from '../store/query.store';
import { AnalyticalReportUiStore } from '../store/ui.store';
import { ChatSessionStore } from '../store/chat-session.store';
import { ChatSessionService } from '../chat/services/chat-session.service';

@Injectable()
export class AnalyticalReportReportingService {
  private readonly assetsStore = inject(AnalyticalReportAssetsStore);
  private readonly dateStore = inject(AnalyticalReportDateStore);
  private readonly queryStore = inject(AnalyticalReportQueryStore);
  private readonly uiStore = inject(AnalyticalReportUiStore);
  private readonly chatSessionStore = inject(ChatSessionStore);
  private readonly reportGenerationService = inject(ReportGenerationService);
  private readonly conversationHistoryService = inject(
    ConversationHistoryService,
  );
  private readonly chatSessionService = inject(ChatSessionService);

  buildReportGenerationRequest(): ReportGenerationRequest | null {
    const assetIds = this.assetsStore.selectedAssetIds();
    if (assetIds.length === 0) return null;

    const startDate = this.dateStore.startDate();
    const endDate = this.dateStore.endDate();
    if (isNullOrUndefined(startDate) || isNullOrUndefined(endDate)) return null;

    const config = this.uiStore.pendingReportConfig();
    const session = this.chatSessionStore.session();
    const sessionId = session?.id ?? '';
    const companyId = session?.context.clientId ?? '';

    const fallbackReportType = (): ReportType => {
      const types = this.queryStore.selectedDataTypesList();
      if (types.includes('trips')) return 'trip_history_daily_summary';
      if (types.includes('alerts')) return 'alerts';
      return 'daily_utilisation';
    };

    const reportType = config?.reportType ?? fallbackReportType();
    const columns =
      config?.columns ??
      this.reportGenerationService.getDefaultColumns(reportType);
    const columnCategories = config?.columnCategories ?? ['standard', 'total'];

    return {
      conversation_id: sessionId,
      company_id: companyId,
      report_type: reportType,
      vehicle_ids: assetIds,
      vehicle_names: this.assetsStore.selectedVehicleNames(),
      start_date: startDate.toISOString(),
      end_date: endDate.toISOString(),
      columns,
      column_categories: columnCategories,
      output_format: config?.outputFormat ?? 'xlsx',
      include_ai_analysis: config?.includeAiAnalysis ?? true,
    };
  }

  async generateReportFile(): Promise<{
    report: ReportGenerationResponse | null;
    error: string | null;
  }> {
    const reportRequest = this.buildReportGenerationRequest();

    if (!reportRequest) {
      return {
        report: null,
        error:
          'Could not build report request. Please ensure vehicles and dates are selected.',
      };
    }

    this.uiStore.setIsGeneratingFile(true);
    const result =
      await this.reportGenerationService.generateReport(reportRequest);
    this.uiStore.setIsGeneratingFile(false);

    if (result) {
      await this.refreshSessionAfterGeneration();
      return { report: result, error: null };
    }

    return {
      report: null,
      error:
        this.reportGenerationService.error() ?? 'Report generation failed.',
    };
  }

  async generateFromDrawer(result: ReportConfigDrawerResult): Promise<{
    report: ReportGenerationResponse | null;
    error: string | null;
  }> {
    const request: ReportGenerationRequest = {
      conversation_id: result.conversationId,
      company_id: result.companyId,
      report_type: result.reportConfig.reportType,
      vehicle_ids: result.vehicleIds,
      vehicle_names: result.vehicleNames,
      start_date: result.startDate.toISOString(),
      end_date: result.endDate.toISOString(),
      columns: result.reportConfig.columns,
      column_categories: result.reportConfig.columnCategories,
      output_format: result.reportConfig.outputFormat,
      include_ai_analysis: result.reportConfig.includeAiAnalysis,
    };

    this.uiStore.setIsGeneratingFile(true);
    const response = await this.reportGenerationService.generateReport(request);
    this.uiStore.setIsGeneratingFile(false);

    if (response) {
      await this.refreshSessionAfterGeneration();
      return { report: response, error: null };
    }

    return {
      report: null,
      error:
        this.reportGenerationService.error() ?? 'Report generation failed.',
    };
  }

  private async refreshSessionAfterGeneration(): Promise<void> {
    this.conversationHistoryService.refreshList();
    const sessionId = this.chatSessionStore.session()?.id;
    if (isDefined(sessionId)) {
      await this.chatSessionService.loadExistingSession(sessionId);
    }
  }
}
