import {
  Component,
  inject,
  input,
  output,
  signal,
  ElementRef,
  ViewChild,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { TooltipModule } from 'primeng/tooltip';
import { ChatSoundService } from '../../services/chat-sound.service';

@Component({
  selector: 'app-chat-input',
  imports: [CommonModule, FormsModule, ButtonModule, TooltipModule],
  templateUrl: './chat-input.component.html',
  styleUrl: './chat-input.component.scss',
})
export class ChatInputComponent {
  private readonly soundService = inject(ChatSoundService);

  // Inputs
  disabled = input(false);
  placeholder = input('Type your message...');
  isLoading = input(false);

  // Outputs
  messageSent = output<string>();

  // Local state
  messageText = signal('');

  @ViewChild('inputField') inputField!: ElementRef<HTMLTextAreaElement>;

  onSend(): void {
    const trimmed = this.messageText().trim();
    if (trimmed && !this.disabled() && !this.isLoading()) {
      this.soundService.playSendMessageSound();
      this.messageSent.emit(trimmed);
      this.messageText.set('');
      this.resetTextareaHeight();
    }
  }

  onKeyDown(event: KeyboardEvent): void {
    if (event.key === 'Enter' && !event.shiftKey) {
      event.preventDefault();
      this.onSend();
    }
  }

  onInput(event: Event): void {
    const target = event.target as HTMLTextAreaElement;
    this.messageText.set(target.value);
    this.autoResizeTextarea(target);
  }

  private autoResizeTextarea(textarea: HTMLTextAreaElement): void {
    textarea.style.height = 'auto';
    const maxHeight = 150; // Max height in pixels
    textarea.style.height = Math.min(textarea.scrollHeight, maxHeight) + 'px';
  }

  private resetTextareaHeight(): void {
    if (this.inputField?.nativeElement !== undefined) {
      this.inputField.nativeElement.style.height = 'auto';
    }
  }

  focus(): void {
    this.inputField?.nativeElement?.focus();
  }
}
