import {
  Component,
  input,
  output,
  computed,
  signal,
  inject,
  ViewChild,
} from '@angular/core';
import {
  isDefined,
  isNullOrUndefined,
} from '../../../../../../../shared/utils';
import { AnalyticalReportAssetsStore } from '../../../store/assets.store';
import { AnalyticalReportDateStore } from '../../../store/date.store';
import { AnalyticalReportQueryStore } from '../../../store/query.store';
import { AnalyticalReportSessionStore } from '../../../store/session.store';
import { ChatSessionService } from '../../services/chat-session.service';
import { ConversationHistoryService } from '../../../../../../../core/services/conversation-history.service';
import { getConfidenceDisplay } from '../../utils/confidence.utils';
import { CommonModule, TitleCasePipe } from '@angular/common';
import { Popover, PopoverModule } from 'primeng/popover';
import { CheckboxModule } from 'primeng/checkbox';
import { ButtonModule } from 'primeng/button';
import { FormsModule } from '@angular/forms';
import { DatePickerModule } from 'primeng/datepicker';
import { MultiSelectModule } from 'primeng/multiselect';
import { SelectModule } from 'primeng/select';
import { ChipModule } from 'primeng/chip';

export interface SavedParams {
  vehicleIds?: string[];
  previousVehicleIds?: string[];
  dataTypeIds?: string[];
  previousDataTypeIds?: string[];
  dateRange?: { start: Date; end: Date };
  previousDateRange?: { start: Date; end: Date };
}

export interface HeaderSummary {
  dateRange: { start: Date; end: Date } | null;
  vehicleCount: number;
  vehicleNames: string[];
  dataTypes: string[];
  queryConfidence: number;
  currentQuery: string;
}

export interface VehicleOption {
  id: string;
  name: string;
  selected: boolean;
}

export interface DataTypeOption {
  id: string;
  label: string;
  description: string;
  icon: string;
}

type DatePresetValue = 'today' | 'yesterday' | 'last7' | 'last30' | 'custom';

interface DatePresetOption {
  label: string;
  value: DatePresetValue;
}

const DEFAULT_DATA_TYPES: DataTypeOption[] = [
  {
    id: 'trips',
    label: 'Trips',
    description: 'Journey data with start/end locations',
    icon: 'pi-map-marker',
  },
  {
    id: 'events',
    label: 'Events',
    description: 'Driver behavior events',
    icon: 'pi-exclamation-triangle',
  },
  {
    id: 'telemetry',
    label: 'Telemetry',
    description: 'Real-time sensor data',
    icon: 'pi-chart-line',
  },
  {
    id: 'alerts',
    label: 'Alerts',
    description: 'System alerts and notifications',
    icon: 'pi-bell',
  },
];

@Component({
  selector: 'app-chat-summary-header',
  imports: [
    CommonModule,
    TitleCasePipe,
    PopoverModule,
    CheckboxModule,
    ButtonModule,
    FormsModule,
    DatePickerModule,
    MultiSelectModule,
    SelectModule,
    ChipModule,
  ],
  templateUrl: './chat-summary-header.component.html',
  styleUrl: './chat-summary-header.component.scss',
})
export class ChatSummaryHeaderComponent {
  @ViewChild('vehiclePanel') vehiclePanel!: Popover;
  @ViewChild('datePanel') datePanel!: Popover;
  @ViewChild('dataTypesPanel') dataTypesPanel!: Popover;

  private readonly assetsStore = inject(AnalyticalReportAssetsStore);
  private readonly dateStore = inject(AnalyticalReportDateStore);
  private readonly queryStore = inject(AnalyticalReportQueryStore);
  private readonly sessionStore = inject(AnalyticalReportSessionStore);
  private readonly chatSessionService = inject(ChatSessionService);
  private readonly conversationHistoryService = inject(
    ConversationHistoryService,
  );

  isLoading = input<boolean>(false);
  hasReports = input<boolean>(false);

  readonly isReadonly = computed(() => {
    if (!this.chatSessionService.isSessionActive()) return true;

    const id = this.conversationHistoryService.selectedConversationId();
    const conversation = this.conversationHistoryService
      .conversations()
      .find((c) => c.id === id);
    if (isDefined(conversation) && conversation.visibility === 'private') {
      // TODO: restrict editing to conversation owner when user_id is available on conversation
    }

    return false;
  });

  // Read session summary and available vehicles directly from stores
  readonly summary = computed(() => this.sessionStore.headerSummary());
  readonly availableVehicles = computed(() =>
    this.assetsStore.headerAvailableVehicles(),
  );

  // Read selected state directly from stores
  readonly selectedVehicleIds = computed(() =>
    this.assetsStore.headerSelectedVehicleIds(),
  );
  readonly selectedGroups = computed(() => this.assetsStore.selectedGroups());

  // Outputs for editing (keep only those needing root orchestration)
  showReports = output<void>();
  paramsSaved = output<SavedParams>();

  // Pending signals — buffer uncommitted multiselect state until Save is clicked
  private readonly _pendingVehicleIds = signal<string[] | null>(null);
  private readonly _pendingDataTypeIds = signal<string[] | null>(null);
  private readonly _pendingDatePreset = signal<DatePresetValue | null>(null);

  // Dirty computeds — true when pending state differs from committed state
  readonly isDatePresetDirty = computed(() => {
    const pending = this._pendingDatePreset();
    if (isNullOrUndefined(pending)) return false;
    return pending !== this.selectedDatePreset();
  });

  readonly isVehiclesDirty = computed(() => {
    const pending = this._pendingVehicleIds();
    if (isNullOrUndefined(pending)) return false;
    const committed = this.assetsStore.headerSelectedVehicleIds();
    const committedSet = new Set(committed);
    return (
      pending.length !== committed.length ||
      pending.some((id) => !committedSet.has(id))
    );
  });

  readonly isDataTypesDirty = computed(() => {
    const pending = this._pendingDataTypeIds();
    if (isNullOrUndefined(pending)) return false;
    const committed = this.summary().dataTypes;
    const committedSet = new Set(committed);
    return (
      pending.length !== committed.length ||
      pending.some((id) => !committedSet.has(id))
    );
  });

  // Local state for vehicle selection
  localSelectedIds = signal<Set<string>>(new Set());

  // Local state for date range editing
  localDateRange = signal<Date[] | null>(null);

  // Local state for data type selection
  localSelectedDataTypes = signal<Set<string>>(new Set());

  // Today's date for max date picker restriction
  readonly today = new Date();
  readonly datePresetOptions: DatePresetOption[] = [
    { label: 'Today', value: 'today' },
    { label: 'Yesterday', value: 'yesterday' },
    { label: 'Last 7 days', value: 'last7' },
    { label: 'Last 30 days', value: 'last30' },
    { label: 'Custom', value: 'custom' },
  ];

  readonly hasDateRange = computed(() => isDefined(this.summary().dateRange));

  readonly dateRangeText = computed(() => {
    const range = this.summary().dateRange;
    if (!range) return 'Not selected';

    const formatDate = (date: Date) => {
      return date.toLocaleDateString('en-US', {
        month: 'short',
        day: 'numeric',
      });
    };

    const start = formatDate(range.start);
    const end = formatDate(range.end);

    if (start === end) {
      return start;
    }
    return `${start} - ${end}`;
  });

  readonly vehicleText = computed(() => {
    const count = this.summary().vehicleCount;
    if (count === 0) return 'None selected';

    const groups = this.selectedGroups();
    if (groups.length > 0) {
      const groupNames = groups.map((g) => g.name);
      if (groupNames.length === 1) return groupNames[0];
      if (groupNames.length === 2) return groupNames.join(', ');
      return `${groupNames.slice(0, 2).join(', ')} +${groupNames.length - 2} more`;
    }

    if (count === 1) return this.summary().vehicleNames[0] || '1 vehicle';
    if (count <= 2) return this.summary().vehicleNames.join(', ');
    return `${count} vehicles`;
  });

  readonly dataTypesText = computed(() => {
    const types = this.summary().dataTypes;
    if (types.length === 0) return 'None';
    return types.map((t) => this.capitalizeFirst(t)).join(', ');
  });

  readonly confidenceDisplay = computed(() =>
    getConfidenceDisplay(this.summary().queryConfidence),
  );

  readonly confidenceLevel = computed(() => this.confidenceDisplay().level);
  readonly confidenceLabel = computed(() => this.confidenceDisplay().label);

  readonly selectedDatePresetLabel = computed(() => {
    const preset = this._pendingDatePreset() ?? this.selectedDatePreset();
    return (
      this.datePresetOptions.find((o) => o.value === preset)?.label ?? preset
    );
  });

  readonly showConfidence = computed(
    () => this.summary().currentQuery.length > 0,
  );

  readonly hasSummaryContent = computed(() => {
    const s = this.summary();
    return (
      isDefined(s.dateRange) ||
      s.vehicleCount > 0 ||
      s.dataTypes.length > 0 ||
      s.currentQuery.length > 0
    );
  });

  readonly selectedDatePreset = computed<DatePresetValue>(() => {
    const range = this.summary().dateRange;
    if (!range) return 'custom';
    const start = this.toStartOfDay(range.start);
    const end = this.toEndOfDay(range.end);
    const todayStart = this.toStartOfDay(this.today);
    const todayEnd = this.toEndOfDay(this.today);
    const yesterday = new Date(todayStart);
    yesterday.setDate(yesterday.getDate() - 1);
    const yesterdayStart = this.toStartOfDay(yesterday);
    const yesterdayEnd = this.toEndOfDay(yesterday);
    const last7Start = new Date(todayStart);
    last7Start.setDate(last7Start.getDate() - 6);
    const last30Start = new Date(todayStart);
    last30Start.setDate(last30Start.getDate() - 29);

    if (this.sameRange(start, end, todayStart, todayEnd)) return 'today';
    if (this.sameRange(start, end, yesterdayStart, yesterdayEnd))
      return 'yesterday';
    if (this.sameRange(start, end, this.toStartOfDay(last7Start), todayEnd))
      return 'last7';
    if (this.sameRange(start, end, this.toStartOfDay(last30Start), todayEnd))
      return 'last30';
    return 'custom';
  });

  // Multi-select binding for header vehicle dropdown.
  // Getter reads pending state (if any) or falls back to committed; setter only updates pending.
  get selectedVehicleIdsModel(): string[] {
    return this._pendingVehicleIds() ?? this.selectedVehicleIds();
  }

  set selectedVehicleIdsModel(value: string[]) {
    this._pendingVehicleIds.set(value ?? []);
  }

  // Multi-select binding for header data types dropdown.
  get selectedDataTypeIdsModel(): string[] {
    return this._pendingDataTypeIds() ?? this.summary().dataTypes;
  }

  set selectedDataTypeIdsModel(value: string[]) {
    this._pendingDataTypeIds.set(value ?? []);
  }

  readonly isDirty = computed(
    () =>
      this.isDatePresetDirty() ||
      this.isVehiclesDirty() ||
      this.isDataTypesDirty(),
  );

  readonly isSaving = signal(false);

  async saveAll(): Promise<void> {
    this.isSaving.set(true);
    try {
      const contextPatch: {
        vehicle_ids?: string[];
        vehicle_names?: Record<string, string>;
        data_types?: string[];
        date_range?: { start_date: string; end_date: string };
      } = {};
      const savedParams: SavedParams = {};

      // Capture pending values before any commits
      const pendingVehicleIds = this.isVehiclesDirty()
        ? this._pendingVehicleIds()
        : null;
      const pendingDataTypeIds = this.isDataTypesDirty()
        ? this._pendingDataTypeIds()
        : null;
      const pendingDatePreset = this.isDatePresetDirty()
        ? this._pendingDatePreset()
        : null;

      if (isDefined(pendingVehicleIds)) {
        savedParams.previousVehicleIds =
          this.assetsStore.headerSelectedVehicleIds();
        savedParams.vehicleIds = pendingVehicleIds;

        const vehicleNames: Record<string, string> = {};
        for (const v of this.availableVehicles()) {
          if (pendingVehicleIds.includes(v.id)) vehicleNames[v.id] = v.name;
        }
        contextPatch.vehicle_ids = pendingVehicleIds;
        contextPatch.vehicle_names = vehicleNames;
      }

      if (isDefined(pendingDataTypeIds)) {
        savedParams.previousDataTypeIds =
          this.queryStore.selectedDataTypesList();
        savedParams.dataTypeIds = pendingDataTypeIds;
        contextPatch.data_types = pendingDataTypeIds;
      }

      if (isDefined(pendingDatePreset) && pendingDatePreset !== 'custom') {
        const oldStart = this.dateStore.startDate();
        const oldEnd = this.dateStore.endDate();
        if (isDefined(oldStart) && isDefined(oldEnd)) {
          savedParams.previousDateRange = { start: oldStart, end: oldEnd };
        }
        const { start, end } = this.resolveDatePreset(pendingDatePreset);
        contextPatch.date_range = {
          start_date: start.toISOString(),
          end_date: end.toISOString(),
        };
        savedParams.dateRange = { start, end };
      }

      if (Object.keys(contextPatch).length === 0) return;

      const sessionId = this.chatSessionService.session()?.id;

      if (isDefined(sessionId) && !sessionId.startsWith('guided-')) {
        try {
          await this.chatSessionService.apiUpdateSession(sessionId, {
            context: contextPatch,
          });
        } catch (error) {
          // PATCH failed — do not commit, leave pending state dirty so user can retry
          console.error('Failed to patch session:', error);
          return;
        }
      }

      // Commit to stores only after successful PATCH (or for guided sessions)
      if (isDefined(pendingVehicleIds)) {
        this.assetsStore.setSelectedAssetIds(pendingVehicleIds);
        this._pendingVehicleIds.set(null);
      }
      if (isDefined(pendingDataTypeIds)) {
        this.queryStore.setSelectedDataTypesList(pendingDataTypeIds);
        this.queryStore.updateDataTypeOptions((options) =>
          options.map((opt) => ({
            ...opt,
            selected: pendingDataTypeIds.includes(opt.value),
          })),
        );
        this._pendingDataTypeIds.set(null);
      }
      if (isDefined(pendingDatePreset) && pendingDatePreset !== 'custom') {
        this.saveDatePreset();
      }

      this.paramsSaved.emit(savedParams);
    } finally {
      this.isSaving.set(false);
    }
  }

  discardChanges(): void {
    this._pendingVehicleIds.set(null);
    this._pendingDataTypeIds.set(null);
    this._pendingDatePreset.set(null);
  }

  private capitalizeFirst(str: string): string {
    return str.charAt(0).toUpperCase() + str.slice(1);
  }

  // Computed for local vehicle options with selection state
  readonly localVehicleOptions = computed(() => {
    const available = this.availableVehicles();
    const selectedIds = this.localSelectedIds();
    return available.map((v) => ({
      ...v,
      selected: selectedIds.has(v.id),
    }));
  });

  // Handle date item click - opens date picker panel
  onDateClick(event: Event): void {
    // Sync local state from parent input before opening
    const range = this.summary().dateRange;
    if (range) {
      this.localDateRange.set([range.start, range.end]);
    } else {
      this.localDateRange.set(null);
    }
    this.datePanel?.toggle(event);
  }

  onDatePresetChange(preset: DatePresetValue, event?: Event): void {
    if (this.isReadonly()) return;

    if (preset === 'custom') {
      const openEvent = event ?? new Event('click');
      this.onDateClick(openEvent);
      return;
    }

    this._pendingDatePreset.set(preset);
  }

  private resolveDatePreset(preset: Exclude<DatePresetValue, 'custom'>): {
    start: Date;
    end: Date;
  } {
    const now = new Date();
    const end = this.toEndOfDay(now);
    const start = this.toStartOfDay(now);

    if (preset === 'yesterday') {
      start.setDate(start.getDate() - 1);
      end.setDate(end.getDate() - 1);
    } else if (preset === 'last7') {
      start.setDate(start.getDate() - 6);
    } else if (preset === 'last30') {
      start.setDate(start.getDate() - 29);
    }

    return { start, end };
  }

  saveDatePreset(): void {
    const preset = this._pendingDatePreset();
    if (!preset || preset === 'custom') return;

    const { start, end } = this.resolveDatePreset(preset);

    this.localDateRange.set([start, end]);
    this.dateStore.setDateRange(start, end);
    this.dateStore.setActiveDatePreset(null);
    this._pendingDatePreset.set(null);
  }

  get selectedDatePresetModel(): string {
    return this._pendingDatePreset() ?? this.selectedDatePreset();
  }

  set selectedDatePresetModel(value: DatePresetValue) {
    if (value === 'custom') {
      this._pendingDatePreset.set(null);
      return;
    }
    this._pendingDatePreset.set(value);
  }

  // Handle vehicle item click - opens vehicle selection panel
  onVehicleClick(event: Event): void {
    // Sync local state from store before opening
    this.localSelectedIds.set(
      new Set(this.assetsStore.headerSelectedVehicleIds()),
    );
    this.vehiclePanel?.toggle(event);
  }

  // Toggle individual vehicle selection
  toggleVehicle(vehicleId: string): void {
    this.localSelectedIds.update((ids) => {
      const newIds = new Set(ids);
      if (newIds.has(vehicleId)) {
        newIds.delete(vehicleId);
      } else {
        newIds.add(vehicleId);
      }
      return newIds;
    });
  }

  // Check if a vehicle is selected
  isVehicleSelected(vehicleId: string): boolean {
    return this.localSelectedIds().has(vehicleId);
  }

  // Apply vehicle selection changes
  applyVehicleChanges(): void {
    const selectedIds = Array.from(this.localSelectedIds());
    this.assetsStore.setSelectedAssetIds(selectedIds);
    this.vehiclePanel?.hide();
  }

  // Cancel vehicle selection changes
  cancelVehicleChanges(): void {
    // Reset to original selection
    const ids = this.assetsStore.headerSelectedVehicleIds();
    this.localSelectedIds.set(new Set(ids));
    this.vehiclePanel?.hide();
  }

  // Handle date range selection - called on each date selection in range mode
  onDateRangeSelect(_date: Date): void {
    // The localDateRange signal is already bound via ngModel,
    // so we just need to trigger any side effects here if needed
  }

  // Apply date range changes
  applyDateChanges(): void {
    const range = this.localDateRange();
    if (
      isDefined(range) &&
      range.length === 2 &&
      isDefined(range[0]) &&
      isDefined(range[1])
    ) {
      this.dateStore.setDateRange(range[0], range[1]);
      this.dateStore.setActiveDatePreset(null);
    }
    this.datePanel?.hide();
  }

  // Cancel date range changes
  cancelDateChanges(): void {
    // Reset to original range
    const range = this.summary().dateRange;
    if (range) {
      this.localDateRange.set([range.start, range.end]);
    } else {
      this.localDateRange.set(null);
    }
    this.datePanel?.hide();
  }

  private toStartOfDay(date: Date): Date {
    return new Date(
      date.getFullYear(),
      date.getMonth(),
      date.getDate(),
      0,
      0,
      0,
      0,
    );
  }

  private toEndOfDay(date: Date): Date {
    return new Date(
      date.getFullYear(),
      date.getMonth(),
      date.getDate(),
      23,
      59,
      59,
      999,
    );
  }

  private sameRange(
    aStart: Date,
    aEnd: Date,
    bStart: Date,
    bEnd: Date,
  ): boolean {
    return (
      aStart.getTime() === bStart.getTime() && aEnd.getTime() === bEnd.getTime()
    );
  }

  // ============================================================================
  // Data Types Panel Methods
  // ============================================================================

  // Available data type options
  readonly availableDataTypeOptions = computed(() => DEFAULT_DATA_TYPES);

  // Check if a data type is selected
  isDataTypeSelected(dataTypeId: string): boolean {
    return this.localSelectedDataTypes().has(dataTypeId);
  }

  // Count of new data types to add (excluding already in summary)
  readonly newDataTypeSelectionCount = computed(() => {
    const selected = this.localSelectedDataTypes();
    const currentTypes = new Set(this.summary().dataTypes);

    return Array.from(selected).filter((id) => !currentTypes.has(id)).length;
  });

  // Handle data types click - opens data types panel
  onDataTypesClick(event: Event): void {
    // Sync local state from parent input before opening
    this.localSelectedDataTypes.set(new Set(this.summary().dataTypes));
    this.dataTypesPanel?.toggle(event);
  }

  // Toggle individual data type selection
  toggleDataType(dataTypeId: string): void {
    this.localSelectedDataTypes.update((ids) => {
      const newIds = new Set(ids);
      if (newIds.has(dataTypeId)) {
        newIds.delete(dataTypeId);
      } else {
        newIds.add(dataTypeId);
      }
      return newIds;
    });
  }

  // Apply data type changes
  applyDataTypeChanges(): void {
    const selectedTypes = Array.from(this.localSelectedDataTypes());
    this.queryStore.setSelectedDataTypesList(selectedTypes);
    this.queryStore.updateDataTypeOptions((options) =>
      options.map((opt) => ({
        ...opt,
        selected: selectedTypes.includes(opt.value),
      })),
    );
    this.dataTypesPanel?.hide();
  }

  // Cancel data type changes
  cancelDataTypeChanges(): void {
    // Reset to original selection
    const currentTypes = this.summary().dataTypes;
    this.localSelectedDataTypes.set(new Set(currentTypes));
    this.dataTypesPanel?.hide();
  }
}
