import { Component, input, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { CardModule } from 'primeng/card';
import { ProgressBarModule } from 'primeng/progressbar';

import {
  CollectedDataSummary,
  VehicleCollectionProgress,
  DataType,
} from '../../models/chat.interface';

@Component({
  selector: 'app-query-preview',
  imports: [CommonModule, CardModule, ProgressBarModule],
  templateUrl: './query-preview.component.html',
  styleUrl: './query-preview.component.scss',
})
export class QueryPreviewComponent {
  // Inputs
  query = input('');
  confidence = input(0);
  changes = input<string[]>([]);
  isLoading = input(false);

  // Data collection status
  isCollecting = input(false);
  collectionProgress = input(0);
  collectedData = input<CollectedDataSummary | null>(null);

  // Detailed collection status
  dataTypes = input<DataType[]>([]);
  statusMessage = input('');
  currentVehicle = input('');
  vehicleProgress = input<VehicleCollectionProgress[]>([]);

  // Computed properties
  readonly hasQuery = computed(() => this.query().length > 0);
  readonly hasChanges = computed(() => this.changes().length > 0);
  readonly hasCollectedData = computed(() => this.collectedData() !== null);
  readonly hasVehicleProgress = computed(
    () => this.vehicleProgress().length > 0,
  );

  // Format data types for display
  readonly dataTypesLabel = computed(() => {
    const types = this.dataTypes();
    if (types.length === 0) return '';
    return types.map((t) => t.charAt(0).toUpperCase() + t.slice(1)).join(', ');
  });

  // Get completed vehicles count
  readonly completedVehiclesCount = computed(() => {
    return this.vehicleProgress().filter((v) => v.status === 'complete').length;
  });

  // Get total records collected so far
  readonly totalRecordsCollected = computed(() => {
    return this.vehicleProgress().reduce(
      (sum, v) => sum + v.recordsCollected,
      0,
    );
  });

  readonly confidenceColor = computed(() => {
    const conf = this.confidence();
    if (conf >= 80) return 'high';
    if (conf >= 50) return 'medium';
    return 'low';
  });

  readonly confidenceLabel = computed(() => {
    const conf = this.confidence();
    if (conf >= 90) return 'Ready';
    if (conf >= 70) return 'Good';
    if (conf >= 50) return 'Building';
    return 'Starting';
  });
}
