import {
  Component,
  computed,
  inject,
  input,
  OnInit,
  output,
  signal,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { SkeletonModule } from 'primeng/skeleton';
import { TooltipModule } from 'primeng/tooltip';
import { BadgeModule } from 'primeng/badge';
import { MenuItem } from 'primeng/api';

import {
  ConversationSummary,
  GroupedConversations,
} from '../../../../../../../core/interfaces/conversation.interface';
import { ScheduleItem } from '../../../../../../../core/interfaces/report-generation.interface';
import { ReportGenerationService } from '../../../../../../../core/services/report-generation.service';
import { ConversationHistoryService } from '../../../../../../../core/services/conversation-history.service';
import { cronToHuman } from '../../../../../../../core/utils/schedule.utils';
import { TagModule } from 'primeng/tag';
import { IconFieldModule } from 'primeng/iconfield';
import { InputIconModule } from 'primeng/inputicon';
import { ToggleSwitchModule } from 'primeng/toggleswitch';
import { AccordionModule } from 'primeng/accordion';
import { TimeAgoPipe } from '../../../../../../../shared/pipes/time-ago.pipe';
import { ContextMenuModule } from 'primeng/contextmenu';

@Component({
  selector: 'app-conversation-sidebar',
  imports: [
    CommonModule,
    FormsModule,
    ButtonModule,
    InputTextModule,
    SkeletonModule,
    TooltipModule,
    BadgeModule,
    TagModule,
    IconFieldModule,
    InputIconModule,
    ToggleSwitchModule,
    AccordionModule,
    TimeAgoPipe,
    ContextMenuModule,
  ],
  templateUrl: './conversation-sidebar.component.html',
  styleUrl: './conversation-sidebar.component.scss',
})
export class ConversationSidebarComponent implements OnInit {
  private readonly reportGenerationService = inject(ReportGenerationService);
  private readonly conversationHistoryService = inject(
    ConversationHistoryService,
  );

  readonly cronToHuman = cronToHuman;

  // ============================================================================
  // Inputs
  // ============================================================================

  isCollapsed = input(false);

  // Read state directly from service
  readonly conversations = computed(() =>
    this.conversationHistoryService.groupedConversations(),
  );
  readonly selectedId = computed(() =>
    this.conversationHistoryService.selectedConversationId(),
  );
  readonly isLoading = computed(() =>
    this.conversationHistoryService.isLoading(),
  );

  // ============================================================================
  // Outputs
  // ============================================================================

  newConversation = output<void>();
  conversationSelected = output<string>();
  toggleCollapsed = output<boolean>();
  newSchedule = output<void>();
  openSearch = output<void>();

  // ============================================================================
  // Local state
  // ============================================================================

  searchText = signal('');
  privateMode = signal(false);
  contextMenuConversation = signal<ConversationSummary | null>(null);
  renamingId = signal<string | null>(null);
  renameValue = signal('');

  schedules = signal<ScheduleItem[]>([]);
  schedulesLoading = signal(false);

  // ============================================================================
  // Date group labels
  // ============================================================================

  readonly dateGroups: { key: keyof GroupedConversations; label: string }[] = [
    { key: 'today', label: 'Today' },
    { key: 'yesterday', label: 'Yesterday' },
    { key: 'last7Days', label: 'Previous 7 Days' },
    { key: 'last30Days', label: 'Previous 30 Days' },
    { key: 'older', label: 'Older' },
  ];

  // ============================================================================
  // Computed
  // ============================================================================

  readonly filteredConversations = computed(() => {
    const text = this.searchText().toLowerCase();
    const visibility = this.privateMode()
      ? ('private' as const)
      : ('all' as const);

    const filter = (list: ConversationSummary[]) =>
      list.filter(
        (conversation) =>
          (!text || conversation.title.toLowerCase().includes(text)) &&
          (visibility === 'all' || conversation.visibility === visibility),
      );

    const grouped = this.conversations();
    return {
      today: filter(grouped.today),
      yesterday: filter(grouped.yesterday),
      last7Days: filter(grouped.last7Days),
      last30Days: filter(grouped.last30Days),
      older: filter(grouped.older),
    };
  });

  readonly contextMenuItems = computed<MenuItem[]>(() => {
    const conversation = this.contextMenuConversation();
    if (!conversation) return [];

    return [
      {
        label: 'Rename',
        icon: 'pi pi-pencil',
        command: () => {
          this.renamingId.set(conversation.id);
          this.renameValue.set(conversation.title);
        },
      },
      {
        label:
          conversation.visibility === 'private'
            ? 'Make Public'
            : 'Make Private',
        icon:
          conversation.visibility === 'private' ? 'pi pi-globe' : 'pi pi-lock',
        command: () => {
          void this.conversationHistoryService.updateConversation(
            conversation.id,
            {
              visibility:
                conversation.visibility === 'private' ? 'shared' : 'private',
            },
          );
        },
      },
      { separator: true },
      {
        label: 'Delete',
        icon: 'pi pi-trash',
        styleClass: 'danger-item',
        command: () => {
          void this.conversationHistoryService
            .deleteConversation(conversation.id)
            .then(() => {
              this.conversationHistoryService.refreshList();
            });
        },
      },
    ];
  });

  ngOnInit(): void {
    void this.loadSchedules();
  }

  // ============================================================================
  // Schedule Methods
  // ============================================================================

  async loadSchedules(): Promise<void> {
    this.schedulesLoading.set(true);
    try {
      const items = await this.reportGenerationService.listSchedules();
      this.schedules.set(items);
    } finally {
      this.schedulesLoading.set(false);
    }
  }

  async deleteSchedule(id: string, event: MouseEvent): Promise<void> {
    event.stopPropagation();
    await this.reportGenerationService.deleteSchedule(id);
    await this.loadSchedules();
  }

  async refreshSchedules(): Promise<void> {
    await this.loadSchedules();
  }

  getReportTypeLabel(reportType: string): string {
    const found = this.reportGenerationService
      .getReportTypes()
      .find((r) => r.report_type === reportType);
    return found?.display_name ?? reportType;
  }

  // ============================================================================
  // Methods
  // ============================================================================

  hasNoConversations(
    filtered: ReturnType<typeof this.filteredConversations>,
  ): boolean {
    return this.dateGroups.every((group) => !filtered[group.key].length);
  }

  toggleVisibility(conversation: ConversationSummary, event: Event): void {
    event.stopPropagation();
    const newVisibility =
      conversation.visibility === 'private' ? 'shared' : 'private';
    void this.conversationHistoryService.updateConversation(conversation.id, {
      visibility: newVisibility,
    });
  }

  submitRename(conversation: ConversationSummary): void {
    const newTitle = this.renameValue().trim();
    if (newTitle && newTitle !== conversation.title) {
      void this.conversationHistoryService.updateConversation(conversation.id, {
        title: newTitle,
      });
    }
    this.renamingId.set(null);
    this.renameValue.set('');
  }

  onSelectConversation(id: string): void {
    this.conversationHistoryService.selectConversation(id);
    this.conversationSelected.emit(id);
  }
}
