import { Injectable, inject } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable } from 'rxjs';

import { AuthTokenManagerService } from '../../../../../../core/services/auth-token-manager.service';
import { ApiUrlService } from '../../../../../../core/services/api-url.service';
import { isDefined } from '../../../../../../shared/utils';

@Injectable()
export class ReportingHttpService {
  private readonly http = inject(HttpClient);
  private readonly authTokenManagerService = inject(AuthTokenManagerService);
  private readonly apiUrlService = inject(ApiUrlService);

  private buildBodyAuth(companyId: string): {
    auth_token: string;
    base_url: string;
    company_id: string;
  } {
    return {
      auth_token: this.authTokenManagerService.getAccessToken() ?? '',
      base_url: this.apiUrlService
        .getCurrentApiUrl()
        .replace(/^https?:\/\//, ''),
      company_id: companyId,
    };
  }

  postWithAuth<T>(url: string, body: object, companyId: string): Observable<T> {
    return this.http.post<T>(url, {
      ...this.buildBodyAuth(companyId),
      ...body,
    });
  }

  patchWithAuth<T>(
    url: string,
    body: object,
    companyId: string,
  ): Observable<T> {
    return this.http.patch<T>(url, {
      ...this.buildBodyAuth(companyId),
      ...body,
    });
  }

  getWithAuth<T>(
    url: string,
    params?: Record<string, string>,
    companyId?: string,
  ): Observable<T> {
    // GET endpoints use headers (handled by existing AuthInterceptor), not body auth.
    const authParams = {
      ...(isDefined(companyId) ? { company_id: companyId } : {}),
      ...params,
    };
    return this.http.get<T>(url, {
      params: new HttpParams({ fromObject: authParams }),
    });
  }
}
